
// ---- on-screen error reporter: if anything throws, show it instead of a silent dead screen.
// (diagnostic — surfaces device-specific failures that desktop testing can't reproduce) ----
(function(){
  var seen={}, order=[];
  function text(){
    var badge=''; try{ var m=(document.body.textContent||'').match(/based-cup b\d+/); badge=m?m[0]:'?'; }catch(_){}
    var t='['+badge+'] '+order.length+' unique error(s):\n';
    for(var i=0;i<order.length;i++){ t+='['+seen[order[i]].n+'x] '+seen[order[i]].msg+'\n'; }
    return t;
  }
  function render(){
    var d=document.getElementById('errDiag');
    if(!d){
      d=document.createElement('div'); d.id='errDiag';
      d.style.cssText='position:fixed;left:0;right:0;bottom:0;z-index:99999;background:rgba(150,0,0,.96);color:#fff;font:11px/1.45 monospace;padding:6px 8px;max-height:55%;overflow:auto;-webkit-user-select:text;user-select:text';
      var btn=document.createElement('button'); btn.textContent='📋 COPY ERRORS';
      btn.style.cssText='font:bold 12px monospace;background:#fff;color:#900;border:0;border-radius:6px;padding:6px 12px;margin-bottom:6px';
      btn.onclick=function(){
        var s=text(), done=function(){ btn.textContent='✓ COPIED — paste it to me'; };
        try{ navigator.clipboard.writeText(s).then(done, fb); }catch(e){ fb(); }
        function fb(){ var ta=document.createElement('textarea'); ta.value=s;
          ta.style.cssText='position:fixed;top:0;left:0;width:1px;height:1px;opacity:0';
          document.body.appendChild(ta); ta.focus(); ta.select();
          try{ document.execCommand('copy'); done(); }catch(_){ btn.textContent='select text below & copy'; } ta.remove(); }
      };
      var body=document.createElement('div'); body.id='errDiagBody'; body.style.whiteSpace='pre-wrap';
      d.appendChild(btn); d.appendChild(body);
      (document.body||document.documentElement).appendChild(d);
    }
    document.getElementById('errDiagBody').textContent=text();
  }
  function add(key,msg){ try{ if(seen[key]) seen[key].n++; else { seen[key]={n:1,msg:msg}; order.push(key); } render(); }catch(_){} }
  window.addEventListener('error', function(e){ var m=(e.message||'error'); add(m, m+'  @'+String(e.filename||'').split('/').pop()+':'+(e.lineno||'?')); });
  window.addEventListener('unhandledrejection', function(e){ var r=(e.reason&&e.reason.message)||e.reason||''; add('P:'+r, 'promise: '+r); });
})();
