// ---- Stat-model tuning (Phase 2, b55) — easily tweakable. grabCap is NOT here (stays constant 48). ----
const STEAL_BASE=0.30;        // per-contest steal chance when defender.defense == carrier.dribble (even match)
const STEAL_WEIGHT=0.035;     // +/- chance per point of (defender.def - carrier.drb); halved for the /20 stat scale (b74)
const STEAL_MIN=0.05, STEAL_MAX=0.85;     // clamp on the contest chance (never a guaranteed strip, never 0)
const STEAL_TRY_GAP=22;       // frames between contest attempts during sustained box overlap (~0.37s) — not spammable
const STEAL_COOLDOWN=40;      // frames of grace after a successful steal (~0.67s) — prevents instant steal-back ping-pong
const DRIBBLE_GLUE_MIN=0.30, DRIBBLE_GLUE_MAX=0.55;   // glueBall tightness mapped from dribble /20 (b74)
const DEF_CLOSE_BONUS=0.03;   // off-ball speed bonus per defense point when chasing the carrier; halved for the /20 scale (b74)
// ---- DIVE/LUNGE + FOUL + CARD tuning (b85) — all the key values, named + tweakable. ----
// Lunge = a short forward dash (right-click / mobile LUNGE button) on top of normal movement, distinct
// from the kick (charge+power, untouched) and the steal contest (def-vs-drb, untouched). Diving (/20)
// drives the reach; a player WITHOUT the ball reaches further (a defensive tackle-lunge).
const LUNGE_DIST_BASE=34;        // dash distance (px) at diving 0
const LUNGE_DIST_PER_DIV=2.2;    // +px of dash per diving point (/20) -> diving 18 ≈ +40px
const LUNGE_DEF_BONUS=1.55;      // a lunger WITHOUT the ball (defensive lunge) reaches this much further — tunable
const LUNGE_FRICTION=0.80;       // per-frame decay of the dash velocity (distance ≈ v0/(1-friction))
const LUNGE_DURATION=14;         // frames the dash plays out (~0.23s)
const LUNGE_COOLDOWN=72;         // frames before you can lunge again (~1.2s) — not spammable
const LUNGE_STAMINA=0.16;        // stamina spent per lunge (0..1 bar) — tunable cost
const LUNGE_MIN_STAMINA=0.06;    // need at least this much stamina to lunge at all
// Foul: at lunge contact, did the lunger collect more PLAYER than BALL? Clear, tunable thresholds.
const FOUL_CONTACT_DIST=PLAYER_R*2+7;   // centre-distance at which two bodies count as "in contact"
const FOUL_BALL_REACH=PLAYER_R+BALL_R+7;// distance at which the lunger has "reached the ball"
const FOUL_BALL_MARGIN=12;              // ball must be at least this much CLOSER than the opp body to be a CLEAN ball-win (else FOUL)
// CPU: the AI can lunge to tackle (and can mistime it into a foul), reusing its existing decision logic.
const LUNGE_AI_RANGE=120;        // px: CPU only considers a tackle-lunge within this range of the ball
const MATCH_TIME=60;              // 1:00 per half (goals)
const KEEPAWAY_TIME=90;          // keep-away is a single 1:30 period (no half-time)
function matchLen(){ return gameMode==='keepaway' ? KEEPAWAY_TIME : MATCH_TIME; }

let dpr=1;
function resize(){
  const stage=document.getElementById('stage');
  const rw=stage.clientWidth, rh=stage.clientHeight;
  dpr=Math.min(window.devicePixelRatio||1,2);
  cv.width=W*dpr; cv.height=H*dpr;        // fixed logical buffer, CSS scales it
  ctx.setTransform(dpr,0,0,dpr,0,0);
  ctx.imageSmoothingEnabled=true; ctx.imageSmoothingQuality='high';
}
window.addEventListener('resize',resize);

