// ---- Goal juice (b59): purely-visual explosion + shake + flash + slow-mo. Authoritative reset is unchanged.
//      Synced online via a goalSeq in the snapshot (same proven pattern as the rebound event). ----
const GOAL_SLOWMO_SCALE=0.30;   // strength of the slow-mo beat — set to 1.0 to DISABLE slow-mo entirely
const GOAL_SLOWMO_MS=320;       // how long the slow-mo beat lasts (wall-clock ms)
const GOAL_FX_MS=950;           // total explosion duration (ms)
const GOAL_SHAKE=24;            // initial screen-shake amplitude (px)
// --- slow-mo arming + gating (b60). Slow-mo dilates VISUAL time (sim frame-pulldown + the FX clock); it never
//     touches the match clock (timeLeft), the netcode protocol, or the scoring/half OUTCOME. ---
const SLOWMO_ZONE=110;         // px in front of a goal line where a fast goal-bound shot ARMS the slow-mo (anticipation)
const SLOWMO_BALL_SPEED=6;     // min ball speed toward the goal (px/frame) to count as a real goal-bound shot
const SLOWMO_LAST_SECS=20;     // gate: only inside the last N seconds...
const SLOWMO_MARGIN=1;         // ...of the 2nd half, and only when the pre-goal score margin <= this (tied / one-goal game)
// Pass 2 (b66): only arm if the DEFENDER physically can't reach the ball's path before it crosses the line.
const SLOWMO_DEF_SPEED_K=1.0;  // multiplier on the defender's max speed in the reach calc (<1 = more generous toward arming)
const SLOWMO_REACH_MARGIN=14;  // px the defender must BEAT the ball's path by to count as "can stop" (higher = arms more)
const SLOWMO_POST_GRACE=34;    // px past the goal mouth the path may exit and still arm (near-post drama); beyond = clear miss -> no slow-mo
let SLOWMO_DEBUG=false;        // set true (here/console) to console.log the reach calc when a goal-bound shot is evaluated
const SLOWMO_ZOOM=1.5;         // cinematic zoom-in during slow-mo (1.0 = no zoom)
const SLOWMO_ZOOM_EASE=0.14;   // how fast the zoom eases in/out
const SLOWMO_FOLLOW_EASE=0.35; // how tightly the camera tracks its focus (ball/goal) during slow-mo — higher = snappier
let FORCE_GOAL_SLOWMO=false;   // DEBUG: set true (here, or live in the console) => EVERY goal slow-mos, ignoring the gate
let slowmoT=0, netSlowmo=false, motionScale=1;   // slow-mo remaining (s) · guest's streamed flag · eased per-frame motion scale (SMOOTH slow-mo, no frame-skip)
let camZoom=1, camFocusX=W/2, camFocusY=H/2;     // cinematic camera: zoom + focus during slow-mo
let slowmoCamMode='ball', slowmoCamSide='R';     // 'ball'=follow the ball (long-range shot) · 'goal'=lock on the target goal (short-range). Side = which goal.
let netCamMode='ball', netCamSide='R';           // guest copies, streamed from the host so both see the same framing
let goalFx=null, shakeAmp=0;    // active explosion + screen-shake amplitude
let goalSeq=0, goalFxSide='', goalSeen=0;   // streamed goal-event counter (host increments, guest detonates on change)
// b85: foul/card event — host-authoritative, streamed like goalSeq (host increments + flashes the card + runs the reset; guest mirrors)
let foulSeq=0, foulSeen=0, foulCardType=0, foulCardSide='';   // counter · 1=yellow 2=red · which side was carded
let cardFxTimer=null, lungeReq=false;       // card-flash auto-hide timer · pending local lunge request (right-click / mobile button, edge)
let gameMode='goals', possP=0, possT=0;   // keepaway mode: hold the ball longest
let half=1, halftime=false;               // two 1-minute halves
let timeLeft=MATCH_TIME, golden=false, lastTs=0, kickoffLock=0;

function mkPlayer(x,y,who,char){ const d=statDerived(char);
  return {x,y,vx:0,vy:0,who,char,face:who==='p'?1:-1,
    kickCD:0,boost:0, aim: who==='p'?0:Math.PI, stamina:1, sprinting:false, charge:0, charging:false,
    maxOn:d.maxOn, maxOff:d.maxOff, kickPow:d.kickPow, stamDrain:d.stamDrain, stamRegen:d.stamRegen,
    defense:d.defense, dribble:d.dribble, grab:d.grab, dive:d.dive,
    lvx:0, lvy:0, lunging:0, lungeCD:0, lungeFoulDone:false,  // b85: lunge dash state
    cards:0, out:false}; }                                    // b85: cards (0=clean,1=yellow,2=red) + removed-from-match flag
function reset(concededBy){
  const oc = oppChar || (humanChar==='pepe'?'trumpe':'pepe');
  players={ p:mkPlayer(W*0.27,H/2,'p',humanChar), t:mkPlayer(W*0.73,H/2,'t',oc) };
  ball={x:W/2,y:H/2,vx:0,vy:0, owner:null, kickLock:18};
  if(concededBy==='t'){ ball.x=W*0.64; ball.vx=1.2; }
  else if(concededBy==='p'){ ball.x=W*0.36; ball.vx=-1.2; }
  kickFlash=0; kickoffLock=55;
}
function newGame(){score={p:0,t:0}; possP=0; possT=0; half=1; halftime=false; timeLeft=matchLen(); golden=false;
  clearTimeout(htTimer); hideHalftime();
  setMeta(''); updateHUD(); reset(); goalLock=0;
  goalSeq=0; goalSeen=0; goalFx=null; shakeAmp=0;
  foulSeq=0; foulSeen=0; foulCardType=0; foulCardSide=''; lungeReq=false;   // b85: fresh card state each match
  slowmoT=0; netSlowmo=false; motionScale=1; camZoom=1; camFocusX=W/2; camFocusY=H/2;
  slowmoCamMode='ball'; slowmoCamSide='R'; netCamMode='ball'; netCamSide='R';   // reset goal-juice + slow-mo + camera each match
  startMatchStats();}   // BUILD 2: fresh per-character stat accumulator for this match
function halfLabel(){ if(gameMode==='keepaway') return 'KEEP-AWAY · HOLD IT';
  return half===2?'2ND HALF':'1ST HALF'; }

function fmtTime(t){const m=Math.max(0,Math.floor(t/60)), s=Math.max(0,Math.floor(t%60));
  return m+':'+String(s).padStart(2,'0');}
function setMeta(t){document.getElementById('metaLabel').textContent=t;}
function setStam(id,pl){const el=document.getElementById(id); if(!el||!pl)return;
  el.style.width=(clamp(pl.stamina,0,1)*100)+'%';
  el.classList.toggle('spr', pl.sprinting);
  el.classList.toggle('low', !pl.sprinting && pl.stamina<0.25);}
function updateHUD(){
  if(gameMode==='keepaway'){
    document.getElementById('pScore').textContent=Math.floor(possP)+'s';
    document.getElementById('tScore').textContent=Math.floor(possT)+'s';
    if(players && !halftime){            // live "who's winning" readout
      const dp=possP-possT;
      setMeta('⏱️ '+(Math.abs(dp)<0.5 ? 'EVEN — grab the ball!'
        : (dp>0?STATS[players.p.char].name:STATS[players.t.char].name)+' AHEAD'));
    }
  } else {
    document.getElementById('pScore').textContent=score.p;
    document.getElementById('tScore').textContent=score.t;
  }
  const cl=document.getElementById('clock');
  cl.textContent= golden?'GG':fmtTime(timeLeft);
  cl.classList.toggle('low', !golden && timeLeft<=10);
  if(players){ setStam('pStam',players.p); setStam('tStam',players.t);
    const cmark=n=>n>=2?'🟥':(n>=1?'🟨':'');                       // b85: show the player's current card on their HUD card
    const pm=document.getElementById('pCardMark'), tm=document.getElementById('tCardMark');
    if(pm) pm.textContent=cmark(players.p.cards||0); if(tm) tm.textContent=cmark(players.t.cards||0); }
  const pt=document.getElementById('pingTag');
  if(pt){ if(netRole && NET.rtt!=null){ pt.classList.remove('hide');
      const r = NET.rttShown!=null?NET.rttShown:NET.rtt;
      const q = r<60?'🟢':r<120?'🟡':'🔴';
      pt.textContent = q+' ping '+r+'ms'+(NET.p2p?' ⚡':'');   // ⚡ = direct P2P (no relay hop)
      // paired with the pot pill; centre the lone ping pill when there's no wager
      pt.style.transform = document.getElementById('potTag').classList.contains('hide') ? 'translateX(-50%)' : 'translateX(4%)'; }
    else pt.classList.add('hide'); }
}

// ---- Input ----
const keys={};
addEventListener('keydown',e=>{
  if(e.target && e.target.tagName==='INPUT') return;   // let form fields work normally
  if(typeof e.key!=='string') return;   // synthetic events (browser autofill / extensions e.g. Phantom) fire with key/code undefined -> e.key.toLowerCase() threw (b53)
  if(['ArrowUp','ArrowDown','ArrowLeft','ArrowRight'].includes(e.key)) e.preventDefault();
  keys[e.key.toLowerCase()]=true; if(typeof e.code==='string') keys[e.code.toLowerCase()]=true;
  if(e.key.toLowerCase()==='p' || e.key==='Escape'){ if(state==='play'||state==='paused') togglePause(); }
});
addEventListener('keyup',e=>{ if(typeof e.key!=='string') return; keys[e.key.toLowerCase()]=false; if(typeof e.code==='string') keys[e.code.toLowerCase()]=false;});

// mouse: aim toward cursor, left-click kicks
const mouse={x:W/2,y:H/2,active:false};
function toLogical(e){const r=cv.getBoundingClientRect();
  return {x:(e.clientX-r.left)/r.width*W, y:(e.clientY-r.top)/r.height*H};}
cv.addEventListener('mousemove',e=>{const p=toLogical(e);mouse.x=p.x;mouse.y=p.y;mouse.active=true;});
cv.addEventListener('mouseenter',()=>{mouse.active=true;});
cv.addEventListener('mouseleave',()=>{mouse.active=false;});
cv.addEventListener('mousedown',e=>{ if(e.button===0)keys['kick']=true; else if(e.button===2){ lungeReq=true; e.preventDefault(); } });   // b85: RIGHT-CLICK = lunge (edge); left-click still kicks
addEventListener('mouseup',e=>{if(e.button===0)keys['kick']=false;});
cv.addEventListener('contextmenu',e=>e.preventDefault());

// touch joystick — bind to ONE finger by its identifier so a second finger (KICK) can never
// hijack the stick. The old code read touches[0] (the oldest finger on screen), which made the
// stick jump/freeze at a half-deflected position whenever KICK was held first.
let joyVec={x:0,y:0}, joyActive=false, touchKick=false, touchSprint=false, joyId=null;
const joy=document.getElementById('joy'), stick=document.getElementById('stick');
function joyXY(t){const r=joy.getBoundingClientRect();
  let dx=t.clientX-(r.left+r.width/2), dy=t.clientY-(r.top+r.height/2);
  const mag=Math.hypot(dx,dy), max=r.width/2;
  if(mag>max){dx=dx/mag*max; dy=dy/mag*max;}
  stick.style.left=(50+dx/max*40)+'%'; stick.style.top=(50+dy/max*40)+'%';
  joyVec={x:dx/max,y:dy/max};
  touchSprint = (mag/max) > 0.9;}      // shove the stick to the rim to sprint (no extra button)
function joyFinger(e){ for(const t of e.changedTouches){ if(t.identifier===joyId) return t; } return null; }
joy.addEventListener('touchstart',e=>{const t=e.changedTouches[0]; joyId=t.identifier; joyActive=true; joyXY(t); e.preventDefault();},{passive:false});
joy.addEventListener('touchmove',e=>{const t=joyFinger(e); if(t) joyXY(t); e.preventDefault();},{passive:false});
function joyRelease(e){ if(joyFinger(e)){ joyActive=false; touchSprint=false; joyVec={x:0,y:0}; joyId=null; stick.style.left='50%'; stick.style.top='50%'; } e.preventDefault(); }
joy.addEventListener('touchend',joyRelease,{passive:false});
joy.addEventListener('touchcancel',joyRelease,{passive:false});
const kickBtn=document.getElementById('kickBtn');
kickBtn.addEventListener('touchstart',e=>{touchKick=true;e.preventDefault()},{passive:false});
kickBtn.addEventListener('touchend',e=>{touchKick=false;e.preventDefault()},{passive:false});
kickBtn.addEventListener('touchcancel',e=>{touchKick=false;e.preventDefault()},{passive:false});
// b85: dedicated mobile LUNGE button — distinct from KICK; sets the same edge-triggered request
const lungeBtn=document.getElementById('lungeBtn');
if(lungeBtn){ lungeBtn.addEventListener('touchstart',e=>{ lungeReq=true; e.preventDefault(); },{passive:false}); }

// ---- Audio (all synthesized — no external files) ----
let actx=null, master=null, NOISE=null, muted=false;
function audioInit(){
  if(actx){ if(actx.state==='suspended')actx.resume(); return; }
  try{ actx=new (window.AudioContext||window.webkitAudioContext)(); }catch(e){ return; }
  master=actx.createGain(); master.gain.value=muted?0:0.85; master.connect(actx.destination);
  const sr=actx.sampleRate, len=Math.floor(sr*2);
  NOISE=actx.createBuffer(1,len,sr); const d=NOISE.getChannelData(0);
  for(let i=0;i<len;i++) d[i]=Math.random()*2-1;
}
addEventListener('pointerdown',()=>{ audioInit(); if(!$('splashScreen').classList.contains('hide') && musicMode!=='theme') startMusic('theme'); });
function toggleMute(){ muted=!muted; if(master)master.gain.value=muted?0:0.85;
  document.getElementById('muteBtn').textContent=muted?'🔇':'🔊'; }

// ---- Procedural background music (theme for the intro, calm pad for the lobby) ----
let musicGain=null, musicTimer=null, musicMode=null, musicStep=0, musicNextTime=0;
const CHORDS={
  Am:{bass:110.00, notes:[220.00,261.63,329.63]},
  F :{bass:87.31,  notes:[174.61,220.00,261.63]},
  C :{bass:130.81, notes:[261.63,329.63,392.00]},
  G :{bass:98.00,  notes:[196.00,246.94,293.66]}
};
const PROG=['Am','F','C','G'];
function mnote(freq,t,dur,type,vol){
  if(!actx||!musicGain)return;
  const o=actx.createOscillator(); o.type=type||'sine'; o.frequency.setValueAtTime(freq,t);
  const g=actx.createGain(); g.gain.setValueAtTime(0.0001,t); g.gain.exponentialRampToValueAtTime(vol,t+0.02);
  g.gain.exponentialRampToValueAtTime(0.0001,t+dur);
  o.connect(g).connect(musicGain); o.start(t); o.stop(t+dur+0.05);
}
function mkick(t){ if(!actx||!musicGain)return; const o=actx.createOscillator(); o.type='sine';
  o.frequency.setValueAtTime(150,t); o.frequency.exponentialRampToValueAtTime(45,t+0.12);
  const g=actx.createGain(); g.gain.setValueAtTime(0.0001,t); g.gain.exponentialRampToValueAtTime(0.7,t+0.005); g.gain.exponentialRampToValueAtTime(0.0001,t+0.16);
  o.connect(g).connect(musicGain); o.start(t); o.stop(t+0.2); }
function mhat(t){ if(!actx||!musicGain||!NOISE)return; const s=actx.createBufferSource(); s.buffer=NOISE;
  const f=actx.createBiquadFilter(); f.type='highpass'; f.frequency.value=7500;
  const g=actx.createGain(); g.gain.setValueAtTime(0.0001,t); g.gain.exponentialRampToValueAtTime(0.10,t+0.004); g.gain.exponentialRampToValueAtTime(0.0001,t+0.05);
  s.connect(f).connect(g).connect(musicGain); s.start(t,0,0.06); }
function playStep(mode,step,t){
  const ch=CHORDS[PROG[Math.floor(step/4)%4]];
  if(mode==='theme'){
    if(step%4===0){ mkick(t); mnote(ch.bass,t,0.20,'sawtooth',0.16); }
    if(step%4===2){ mkick(t); mnote(ch.bass,t,0.16,'sawtooth',0.12); }
    if(step%2===1) mhat(t);
    mnote(ch.notes[step%ch.notes.length]*2, t, 0.15, 'triangle', 0.11);   // bright arp
    if(step%8===6) mnote(ch.notes[2]*2, t, 0.3, 'square', 0.05);
  } else { // calm lobby pad
    if(step%4===0){ ch.notes.forEach(n=> mnote(n,t,2.4,'sine',0.06)); mnote(ch.bass,t,2.4,'sine',0.05); }
    if(step%8===4) mnote(ch.notes[step%ch.notes.length]*2, t, 1.4, 'triangle', 0.035);
  }
}
function scheduleMusic(){
  if(!actx||!musicMode)return;
  const stepLen = musicMode==='theme' ? 0.1875 : 0.5;
  while(musicNextTime < actx.currentTime + 0.25){
    playStep(musicMode, musicStep, musicNextTime);
    musicNextTime += stepLen; musicStep=(musicStep+1)%16;
  }
}
function startMusic(mode){
  if(!actx) audioInit();
  if(!actx) return;
  if(!musicGain){ musicGain=actx.createGain(); musicGain.gain.value=0.0001; musicGain.connect(master); }
  if(musicMode===mode && musicTimer) return;
  const switching=musicMode && musicMode!==mode;
  musicMode=mode;
  if(!switching){ musicStep=0; musicNextTime=actx.currentTime+0.06; }
  const vol = mode==='theme' ? 0.5 : 0.34;
  musicGain.gain.cancelScheduledValues(actx.currentTime);
  musicGain.gain.setValueAtTime(Math.max(0.0001,musicGain.gain.value),actx.currentTime);
  musicGain.gain.linearRampToValueAtTime(vol, actx.currentTime+0.8);
  if(!musicTimer) musicTimer=setInterval(scheduleMusic,60);
}
function stopMusic(){
  musicMode=null;
  if(musicGain&&actx){ musicGain.gain.cancelScheduledValues(actx.currentTime);
    musicGain.gain.setValueAtTime(Math.max(0.0001,musicGain.gain.value),actx.currentTime);
    musicGain.gain.linearRampToValueAtTime(0.0001, actx.currentTime+0.5); }
  if(musicTimer){ clearInterval(musicTimer); musicTimer=null; }
}
function burst(dur,freq,q,vol,type,t){
  if(!actx||!NOISE)return;
  const s=actx.createBufferSource(); s.buffer=NOISE;
  const f=actx.createBiquadFilter(); f.type=type||'bandpass'; f.frequency.value=freq; f.Q.value=q||1;
  const g=actx.createGain(); g.gain.setValueAtTime(vol,t); g.gain.exponentialRampToValueAtTime(0.0001,t+dur);
  s.connect(f).connect(g).connect(master); s.start(t, Math.random()*1.5, dur+0.02);
}
function sfxKick(){ if(!actx)return; const t=actx.currentTime;
  const o=actx.createOscillator(), g=actx.createGain();
  o.type='triangle'; o.frequency.setValueAtTime(260,t); o.frequency.exponentialRampToValueAtTime(80,t+0.1);
  g.gain.setValueAtTime(0.0001,t); g.gain.exponentialRampToValueAtTime(0.5,t+0.005);
  g.gain.exponentialRampToValueAtTime(0.0001,t+0.14);
  o.connect(g).connect(master); o.start(t); o.stop(t+0.16);
  burst(0.05,1700,0.8,0.32,'highpass',t);
}
function sfxStep(spr){ if(!actx)return; burst(0.045, spr?900:640, 1.2, spr?0.14:0.09, 'lowpass', actx.currentTime); }
function sfxGrunt(who){ if(!actx)return; const t=actx.currentTime, low=(who==='trumpe'||who==='t');
  const o=actx.createOscillator(), g=actx.createGain(), f=actx.createBiquadFilter();
  o.type='sawtooth'; const base=low?105:155;
  o.frequency.setValueAtTime(base*1.25,t); o.frequency.exponentialRampToValueAtTime(base*0.78,t+0.16);
  f.type='bandpass'; f.frequency.value=low?520:760; f.Q.value=5;
  g.gain.setValueAtTime(0.0001,t); g.gain.exponentialRampToValueAtTime(0.32,t+0.02);
  g.gain.exponentialRampToValueAtTime(0.0001,t+0.2);
  o.connect(f).connect(g).connect(master); o.start(t); o.stop(t+0.22);
  burst(0.12, low?400:600, 3, 0.10,'bandpass',t);
}
function sfxCheer(){ if(!actx||!NOISE)return; const t=actx.currentTime, dur=1.9;
  // bright crowd bed
  const s=actx.createBufferSource(); s.buffer=NOISE; s.loop=true;
  const f=actx.createBiquadFilter(); f.type='bandpass'; f.Q.value=0.5;
  f.frequency.setValueAtTime(800,t); f.frequency.linearRampToValueAtTime(2200,t+0.4); f.frequency.linearRampToValueAtTime(1200,t+dur);
  const g=actx.createGain();
  g.gain.setValueAtTime(0.0001,t); g.gain.linearRampToValueAtTime(0.4,t+0.16);
  g.gain.setValueAtTime(0.36,t+dur*0.5); g.gain.exponentialRampToValueAtTime(0.0001,t+dur);
  s.connect(f).connect(g).connect(master); s.start(t); s.stop(t+dur);
  // "YEAHHH" — chorus of voices, vowel /æ/→/ɑ/ with a rising pitch
  for(let v=0; v<6; v++){
    const base=125*(1+v*0.018) + (Math.random()*8-4);
    const o=actx.createOscillator(); o.type='sawtooth';
    o.frequency.setValueAtTime(base*0.88,t+0.02);
    o.frequency.linearRampToValueAtTime(base*1.2,t+0.45);
    o.frequency.linearRampToValueAtTime(base*1.04,t+1.25);
    const f1=actx.createBiquadFilter(); f1.type='bandpass'; f1.Q.value=7;
    f1.frequency.setValueAtTime(640,t); f1.frequency.linearRampToValueAtTime(760,t+0.55);
    const f2=actx.createBiquadFilter(); f2.type='bandpass'; f2.Q.value=8;
    f2.frequency.setValueAtTime(1800,t); f2.frequency.linearRampToValueAtTime(1100,t+0.55);
    const vg=actx.createGain();
    vg.gain.setValueAtTime(0.0001,t+0.02); vg.gain.exponentialRampToValueAtTime(0.06,t+0.12);
    vg.gain.setValueAtTime(0.05,t+0.75); vg.gain.exponentialRampToValueAtTime(0.0001,t+1.5);
    o.connect(f1); o.connect(f2); f1.connect(vg); f2.connect(vg); vg.connect(master);
    o.start(t+0.02); o.stop(t+1.55);
  }
  // celebratory whistles
  for(let i=0;i<3;i++){ const o=actx.createOscillator(), og=actx.createGain(), tt=t+0.25+Math.random()*0.8;
    o.type='sine'; o.frequency.setValueAtTime(950+Math.random()*700,tt);
    og.gain.setValueAtTime(0.0001,tt); og.gain.exponentialRampToValueAtTime(0.08,tt+0.03);
    og.gain.exponentialRampToValueAtTime(0.0001,tt+0.3);
    o.connect(og).connect(master); o.start(tt); o.stop(tt+0.32); }
}
function sfxBoom(){ if(!actx)return; const t=actx.currentTime;   // goal-explosion roar (reuses the synth + noise bed)
  const o=actx.createOscillator(), g=actx.createGain();
  o.type='sine'; o.frequency.setValueAtTime(150,t); o.frequency.exponentialRampToValueAtTime(38,t+0.5);
  g.gain.setValueAtTime(0.0001,t); g.gain.exponentialRampToValueAtTime(0.85,t+0.02); g.gain.exponentialRampToValueAtTime(0.0001,t+0.6);
  o.connect(g).connect(master); o.start(t); o.stop(t+0.62);
  if(NOISE){ const s=actx.createBufferSource(); s.buffer=NOISE;
    const f=actx.createBiquadFilter(); f.type='lowpass'; f.frequency.setValueAtTime(1900,t); f.frequency.exponentialRampToValueAtTime(180,t+0.5);
    const ng=actx.createGain(); ng.gain.setValueAtTime(0.0001,t); ng.gain.exponentialRampToValueAtTime(0.6,t+0.01); ng.gain.exponentialRampToValueAtTime(0.0001,t+0.55);
    s.connect(f).connect(ng).connect(master); s.start(t); s.stop(t+0.6); }
}
function footsteps(pl){
  const sp=Math.hypot(pl.vx,pl.vy);
  if(sp>1.8){ pl.stepT=(pl.stepT||0)+1; const iv=pl.sprinting?9:15;
    if(pl.stepT>=iv){pl.stepT=0; sfxStep(pl.sprinting);} }
  else pl.stepT=99;
}

// ---- Physics helpers ----
function clamp(v,a,b){return v<a?a:v>b?b:v;}

const CORN=[[FIELD.l+CORNER,FIELD.t+CORNER,-1,-1],[FIELD.r-CORNER,FIELD.t+CORNER,1,-1],
            [FIELD.l+CORNER,FIELD.b-CORNER,-1,1],[FIELD.r-CORNER,FIELD.b-CORNER,1,1]];
// keep an object (with x,y) inside the rounded pitch; slides around corners
function confineRound(o,r){
  o.x=clamp(o.x,FIELD.l+r,FIELD.r-r);
  o.y=clamp(o.y,FIELD.t+r,FIELD.b-r);
  for(const c of CORN){
    const cx=c[0],cy=c[1];
    if((c[2]<0?o.x<cx:o.x>cx) && (c[3]<0?o.y<cy:o.y>cy)){
      const dx=o.x-cx, dy=o.y-cy, d=Math.hypot(dx,dy), maxd=CORNER-r;
      if(d>maxd){ const nx=dx/(d||1), ny=dy/(d||1); o.x=cx+nx*maxd; o.y=cy+ny*maxd; return {nx,ny}; }
    }
  }
  return null;
}
// ball corner: clamp onto the arc and bounce
function cornerClampBall(){
  for(const c of CORN){
    const cx=c[0],cy=c[1];
    if((c[2]<0?ball.x<cx:ball.x>cx) && (c[3]<0?ball.y<cy:ball.y>cy)){
      const dx=ball.x-cx, dy=ball.y-cy, d=Math.hypot(dx,dy), maxd=CORNER-BALL_R;
      if(d>maxd){ const nx=dx/(d||1), ny=dy/(d||1);
        ball.x=cx+nx*maxd; ball.y=cy+ny*maxd;
        const dot=ball.vx*nx+ball.vy*ny; if(dot>0){ball.vx-=1.7*dot*nx*0.86; ball.vy-=1.7*dot*ny*0.86;}
      }
    }
  }
}

// aim: human -> mouse (or joystick/movement); AI -> toward attacking (left) goal
function setAim(pl){
  if(pl.who==='p'){
    // aim follows the mouse only — movement keys never change kick direction
    if(joyActive && (joyVec.x||joyVec.y)) pl.aim=Math.atan2(joyVec.y,joyVec.x);
    else if(!IS_TOUCH) pl.aim=Math.atan2(mouse.y-pl.y, mouse.x-pl.x);   // touch: hold heading when stick released
    return;
  }
  if(mode!=='2p'){
    const gy=clamp(ball.y, GY0+24, GY1-24);
    pl.aim=Math.atan2(gy-pl.y, FIELD.l-pl.x); return;
  }
  if(Math.hypot(pl.vx,pl.vy)>0.5) pl.aim=Math.atan2(pl.vy,pl.vx);
}

function controlPlayer(pl){
  setAim(pl);
  let ax=0,ay=0;
  if(pl.who==='p'){
    if(keys['w'])ay-=1; if(keys['s'])ay+=1; if(keys['a'])ax-=1; if(keys['d'])ax+=1;
    if(joyActive){ax+=joyVec.x;ay+=joyVec.y;}
  }else{
    if(keys['arrowup'])ay-=1; if(keys['arrowdown'])ay+=1;
    if(keys['arrowleft'])ax-=1; if(keys['arrowright'])ax+=1;
  }
  const m=Math.hypot(ax,ay); if(m>1){ax/=m;ay/=m;}
  const sprint = pl.who==='p' ? (keys['shiftleft']||keys['shift']||touchSprint) : keys['shiftright'];
  if(pl.who==='p' && lungeReq){ lungeReq=false; tryLunge(pl); }   // b85: local human (host/offline) lunges; guest routes via sendGuestInput
  applyMove(pl,ax,ay,sprint);
  let held=false;
  if(pl.who==='p'&&(keys['kick']||touchKick))held=true;
  if(pl.who==='t'&&keys['enter'])held=true;
  chargeKick(pl, held);
}
function applyMove(pl,ax,ay,sprint){
  const moving=Math.hypot(ax,ay)>0.1;
  pl.sprinting = !!sprint && pl.stamina>0.02 && moving;
  pl.stamina = clamp(pl.stamina + (pl.sprinting?-pl.stamDrain:pl.stamRegen), 0, 1);
  const ACC=pl.sprinting?1.25:1.0;
  const base=(ball.owner===pl.who)?pl.maxOn:pl.maxOff;            // on-ball vs off-ball speed split
  let MAX=base*(pl.sprinting?SPRINT_MULT:1)+pl.boost;
  if(ball.owner && ball.owner!==pl.who) MAX+=DEF_CLOSE_BONUS*(pl.defense||5);   // small closing-speed bonus when chasing the carrier
  if(gameMode==='keepaway' && ball.owner===pl.who) MAX*=0.75;   // ball-holder is 25% slower in keep-away
  pl.vx+=ax*ACC; pl.vy+=ay*ACC;
  const sp=Math.hypot(pl.vx,pl.vy);
  if(sp>MAX){pl.vx=pl.vx/sp*MAX; pl.vy=pl.vy/sp*MAX;}
  pl.vx*=0.84; pl.vy*=0.84; pl.x+=pl.vx*motionScale; pl.y+=pl.vy*motionScale;
  if(Math.abs(pl.vx)>0.3) pl.face=pl.vx>0?1:-1;
  confineRound(pl,PLAYER_R);
  if(pl.kickCD>0)pl.kickCD--; pl.boost*=0.9;
  stepLunge(pl);                       // b85: apply the lunge dash on top of normal movement
}
// hold to charge, release to shoot. Power comes from the charge + the character's
// power stat ONLY — never from how fast the player is moving.
const CHARGE_TIME=0.62;   // seconds from tap to full power
function chargeKick(pl, held){
  if(pl.kickCD>0 && !held){ pl.charging=false; pl.charge=0; return; }
  if(held){ pl.charging=true; pl.charge=Math.min(1, pl.charge + (1/(CHARGE_TIME*60))); }
  else if(pl.charging){ const c=pl.charge; pl.charging=false; pl.charge=0; tryKick(pl, c); }
}
function tryKick(pl, chargeAmt){
  if(pl.kickCD>0)return;
  const owns=ball.owner===pl.who;
  const dx=ball.x-pl.x, dy=ball.y-pl.y, d=Math.hypot(dx,dy);
  if(!owns && d>PLAYER_R+BALL_R+24)return;
  const c=(chargeAmt==null?1:chargeAmt);
  const a=pl.aim, power=pl.kickPow*(0.55+0.45*c)*(owns?1:0.9);   // aim + charge only
  ball.vx=Math.cos(a)*power;            // set absolutely — independent of player velocity
  ball.vy=Math.sin(a)*power;
  ball.owner=null; ball.kickLock=16; ball.kicker=pl.who;
  ball.shooter=pl.who; ball.wallBounce=false; ball.oppTouch=false; ball.kickX=pl.x; ball.kickY=pl.y;   // keep-away rebound tracking
  pl.kickCD=14; kickFlash=6;            // no movement boost from kicking
  sfxKick(); sfxGrunt(pl.char);
}

// ---- AI for Trumpe (roams the whole pitch) ----
function aiControl(pl){
  // Difficulty tiers escalate on FIVE axes, not one: reaction time, shot aim+accuracy, corner targeting,
  // defence/interception, and turn-to-turn unpredictability. (AI decision-logic only — stats/grabCap untouched.)
  const D={easy:  {spd:.72, err:48, kick:.50, react:13, aimErr:.40, corner:.15, lead:.04, defend:.15, lunge:.010},
           normal:{spd:.90, err:26, kick:.78, react:5,  aimErr:.16, corner:.62, lead:.16, defend:.55, lunge:.030},
           hard:  {spd:1.0, err:10, kick:.95, react:1,  aimErr:.05, corner:.95, lead:.30, defend:1.0, lunge:.055}}[diff]
        || {spd:.90,err:26,kick:.78,react:5,aimErr:.16,corner:.62,lead:.16,defend:.55,lunge:.030};
  const ka=(gameMode==='keepaway');
  if(pl.aiTick==null){ pl.aiTick=0; pl.aiLastOwner='?'; pl.aiCorner=1; pl.aiLane=0; pl.aiTgt=null; }
  // pick a fresh PLAN each new possession (and rarely mid-possession) so the AI isn't identical every kickoff
  if(ball.owner!==pl.aiLastOwner || Math.random()<0.008){
    pl.aiLastOwner=ball.owner;
    const awayCorner = (players.p.y < H/2) ? 1 : -1;                  // attack the post FARTHER from the human
    pl.aiCorner = (Math.random() < 0.5 + D.corner*0.5) ? awayCorner : -awayCorner;
    pl.aiLane = (Math.random()-.5) * (ka?44:64) * (0.4 + D.defend);   // approach-lane / curl offset (varies the beeline)
  }
  // RE-DECIDE the move target only every D.react frames → a felt reaction gap (easy lags a moving ball, hard tracks it)
  pl.aiTick--;
  if(pl.aiTick<=0 || !pl.aiTgt){
    pl.aiTick=D.react;
    let tx,ty;
    if(ball.owner==='t'){
      if(ka){ tx = players.p.x < W/2 ? W*0.72 : W*0.28; ty = clamp(pl.y + (pl.y<H/2?70:-70), GY0+30, GY1-30); }
      else  { tx=FIELD.l+24; ty=clamp(ball.y+(H/2-ball.y)*0.25 + pl.aiLane*0.5, GY0+14, GY1-14); }   // dribble to goal, varied lane
    }else{
      let bx=ball.x + ball.vx*D.lead*6, by=ball.y + ball.vy*D.lead*6;     // anticipate where the ball is going
      if(ball.owner==='p'){                                              // human attacking → drop goal-side to defend/intercept
        bx = ball.x + (FIELD.r-ball.x)*0.28*D.defend;
        by = ball.y + (clamp(ball.y,GY0,GY1)-ball.y)*0.2;
      }
      tx = bx + PLAYER_R*0.5 + pl.aiLane*0.3; ty = by + pl.aiLane*(ball.owner==='p'?0.25:0.5);
    }
    tx+=(Math.random()-.5)*D.err; ty+=(Math.random()-.5)*D.err;
    pl.aiTgt={x:tx,y:ty};
  }
  let ax=pl.aiTgt.x-pl.x, ay=pl.aiTgt.y-pl.y; const m=Math.hypot(ax,ay)||1; ax/=m; ay/=m;
  if(m>2) pl.aim=Math.atan2(pl.aiTgt.y-pl.y, pl.aiTgt.x-pl.x);          // face the target; shot aim is set explicitly below
  const dd=Math.hypot(ball.x-pl.x, ball.y-pl.y);
  const hd=Math.hypot(players.p.x-pl.x, players.p.y-pl.y);
  const sprint = pl.stamina>0.25 && (dd>175 || ball.owner==='t');
  applyMoveAI(pl,ax*D.spd, ay*D.spd, sprint);
  // b85: CPU tackle-lunge — when it doesn't have the ball and the ball is in lunge range, occasionally dash for it.
  // Aimed at the ball so a good lunge wins it cleanly; a mistimed one collects the player = a foul (CPU can be carded too).
  if(pl.lungeCD<=0 && pl.lunging<=0 && kickoffLock===0 && goalLock<=0 && ball.owner!=='t' && dd<LUNGE_AI_RANGE && Math.random()<D.lunge){
    pl.aim=Math.atan2(ball.y-pl.y, ball.x-pl.x); tryLunge(pl);
  }
  if(kickoffLock>0) kickoffLock--;
  if(ball.owner==='t'){
    if(ka){                             // keep-away: only poke it away under pressure, aimed at centre (never a goal mouth)
      if(kickoffLock===0 && hd<PLAYER_R*2.4 && Math.random()<D.kick*0.4){ pl.aim=Math.atan2(H/2-pl.y, W/2-pl.x); tryKick(pl,0.45); }
    }else if(kickoffLock===0 && pl.x<W*0.46 && Math.random()<D.kick){
      const post = pl.aiCorner>0 ? GY1-16 : GY0+16;                    // SHOOT AT A GOAL CORNER (away from keeper), accuracy by tier
      const aimY = clamp(ball.y + (post-ball.y)*D.corner, GY0+12, GY1-12);
      pl.aim = Math.atan2(aimY-pl.y, FIELD.l-pl.x) + (Math.random()-.5)*D.aimErr;
      tryKick(pl,0.85);
    }
  }else if(kickoffLock===0 && dd<PLAYER_R+BALL_R+16 && Math.random()<D.kick*0.85){
    const post = pl.aiCorner>0 ? GY1-16 : GY0+16;                      // win it and clear toward a corner, not dead straight
    const aimY = clamp(ball.y + (post-ball.y)*D.corner*0.7, GY0+20, GY1-20);
    pl.aim = Math.atan2(aimY-pl.y, FIELD.l-pl.x) + (Math.random()-.5)*D.aimErr;
    tryKick(pl,0.7);
  }
}
function applyMoveAI(pl,ax,ay,sprint){
  const moving=Math.hypot(ax,ay)>0.1;
  pl.sprinting = !!sprint && pl.stamina>0.02 && moving;
  pl.stamina = clamp(pl.stamina + (pl.sprinting?-pl.stamDrain:pl.stamRegen), 0, 1);
  const ACC=pl.sprinting?1.25:1.0;
  const base=((ball.owner===pl.who)?pl.maxOn:pl.maxOff)*0.92;     // on/off split, with the AI's existing 0.92 handicap
  let MAX=base*(pl.sprinting?SPRINT_MULT:1)+pl.boost;
  if(ball.owner && ball.owner!==pl.who) MAX+=DEF_CLOSE_BONUS*(pl.defense||5);   // CPU also gets the closing-speed bonus
  if(gameMode==='keepaway' && ball.owner===pl.who) MAX*=0.75;   // ball-holder is 25% slower in keep-away
  pl.vx+=ax*ACC; pl.vy+=ay*ACC;
  const sp=Math.hypot(pl.vx,pl.vy);
  if(sp>MAX){pl.vx=pl.vx/sp*MAX; pl.vy=pl.vy/sp*MAX;}
  pl.vx*=0.84; pl.vy*=0.84; pl.x+=pl.vx*motionScale; pl.y+=pl.vy*motionScale;
  if(Math.abs(pl.vx)>0.3) pl.face=pl.vx>0?1:-1;
  confineRound(pl,PLAYER_R);
  if(pl.kickCD>0)pl.kickCD--; pl.boost*=0.9;
  stepLunge(pl);                       // b85: CPU lunge dash too
}

// ---- DIVE/LUNGE mechanic + FOUL detection + YELLOW/RED cards (b85). Host-authoritative; the guest
//      mirrors cards/resets via the snapshot (same proven pattern as goalSeq). The lunge is mode-agnostic;
//      the foul/card removal uses ONE general team rule so 2v2 slots in later with no new foul code. ----
function stepLunge(pl){
  if(pl.lungeCD>0) pl.lungeCD--;
  if(pl.lunging>0){
    pl.x += pl.lvx*motionScale; pl.y += pl.lvy*motionScale;   // dash advances on TOP of normal movement (bypasses the speed cap)
    pl.lvx*=LUNGE_FRICTION; pl.lvy*=LUNGE_FRICTION;
    if(Math.abs(pl.lvx)>0.3) pl.face = pl.lvx>0?1:-1;
    pl.lunging--;
    confineRound(pl,PLAYER_R);
  }
}
// fire a lunge: a forward dash in the aim direction, distance scaled by DIVING; defenders (no ball) reach further.
function tryLunge(pl){
  if(!pl || pl.out) return;
  if(pl.lungeCD>0 || pl.lunging>0) return;
  if(kickoffLock>0 || goalLock>0 || halftime) return;
  if(pl.stamina < LUNGE_MIN_STAMINA) return;
  pl.stamina = clamp(pl.stamina - LUNGE_STAMINA, 0, 1);   // small, tunable stamina cost
  pl.lungeCD = LUNGE_COOLDOWN; pl.lunging = LUNGE_DURATION; pl.lungeFoulDone = false;
  const defender = (ball.owner !== pl.who);               // not holding the ball -> defensive lunge -> reaches further
  const div = (pl.dive!=null ? pl.dive : 10);
  let dist = LUNGE_DIST_BASE + div*LUNGE_DIST_PER_DIV;    // DIVING drives the reach
  if(defender) dist *= LUNGE_DEF_BONUS;
  const v0 = dist*(1-LUNGE_FRICTION);                     // initial dash velocity so the decay covers ≈ dist
  pl.lvx = Math.cos(pl.aim)*v0; pl.lvy = Math.sin(pl.aim)*v0;
  try{ sfxGrunt(pl.char); }catch(e){}
}
// GENERAL team model (1v1: each player IS their team). 2v2 later just expands teamPlayers/teamOf — foul code unchanged.
function teamOf(pl){ return pl.who; }
function teamPlayers(team){ return [players[team]]; }                    // 1v1: one player per team
function teamAlive(team){ return teamPlayers(team).some(p=>p && !p.out); }
function otherTeam(team){ return team==='p'?'t':'p'; }                   // 1v1 mapping; 2v2 returns the opposing team id
// run every authoritative frame: did any lunging player make contact? (host/local only — a foul rebuilds players)
function processLunges(){
  if(!players) return;
  const list=[players.p]; if(oppActive) list.push(players.t);
  for(const pl of list){
    if(pl && pl.lunging>0 && !pl.lungeFoulDone){ if(checkLungeFoul(pl)) return; }
  }
}
// at contact: more PLAYER than BALL = foul on the lunger; reaching the BALL first = a clean, legal win.
function checkLungeFoul(pl){
  if(!oppActive || pl.out) return false;
  const opp=players[pl.who==='p'?'t':'p'];
  if(!opp || opp.out) return false;
  const dOpp=Math.hypot(pl.x-opp.x, pl.y-opp.y);
  const dBall=Math.hypot(pl.x-ball.x, pl.y-ball.y);
  const wonBall = dBall<FOUL_BALL_REACH && dBall <= dOpp-FOUL_BALL_MARGIN;   // reached the ball, clearly closer than the body
  if(wonBall){
    pl.lungeFoulDone=true;
    if(ball.owner!==pl.who){ if(ball.owner) ball.oppTouch=true; ball.owner=pl.who; ball.stealCD=STEAL_COOLDOWN; ball.kickLock=0; }  // legal tackle wins it
    return false;
  }
  if(dOpp<FOUL_CONTACT_DIST){          // collected the body (not the ball) -> FOUL on the lunger
    pl.lungeFoulDone=true;
    issueFoul(pl, opp);
    return true;                        // players were rebuilt by the reset — stop processing this frame
  }
  return false;
}
// host/local: first foul = yellow, second = red. A red REMOVES the player; a team forfeits only at 0 players (general rule).
function issueFoul(lunger, fouled){
  if(goalLock>0 || lunger.out) return;
  lunger.cards=(lunger.cards||0)+1;
  const red = lunger.cards>=2;
  foulSeq++; foulCardType=red?2:1; foulCardSide=lunger.who;               // streamed so the guest flashes the same card
  showCard(red?'red':'yellow', STATS[lunger.char].name);
  showToast((red?'🟥 RED — ':'🟨 YELLOW — ')+STATS[lunger.char].name+(red?' sent off!':' (foul)'), red?'#ff6b6b':'#ffd43b');
  if(red){
    lunger.out=true;
    const myTeam=teamOf(lunger);
    if(!teamAlive(myTeam)){             // GENERAL RULE: team reaches 0 players -> it forfeits, the other team wins.
      endGame(otherTeam(myTeam));       // 1v1: the only path — red -> 0 -> opponent wins. host endGame streams st:win; guest mirrors.
      return;
    }
    // (2v2 later: team still has players -> match continues; fall through to the foul reset below.)
  }
  foulReset(fouled.who);               // foul that doesn't end the match: kickoff reset, ball to the FOULED side
}
// reuse the EXISTING goal-kickoff reset; possession to the fouled side (like the conceder after a goal). Cards persist across it.
function foulReset(fouledSide){
  const pc=players.p.cards||0, tc=players.t.cards||0, po=!!players.p.out, to=!!players.t.out;
  reset(fouledSide);                   // SAME flow as a post-goal kickoff (reset() rebuilds players + nudges the ball to the conceder/fouled side)
  players.p.cards=pc; players.t.cards=tc; players.p.out=po; players.t.out=to;   // re-stamp the persistent card state the rebuild cleared
  goalLock=Math.max(goalLock,40);      // brief settle beat (clock pauses, like after a goal)
}

// ---- possession: ball softly sticks to the controller (dribble & spin) ----
function grabCap(pl){ return (pl&&pl.grab)||GRAB_BASE; }  // b74: per-card grab radius (48-52), a VISIBLE stat — the one place the hitbox varies (tightly)
// keep-away: shoot it off the goal frame, win it back before the opponent touches it -> bonus seconds
let rebSeq=0, rebLastSide='', rebSeen=0;   // rebound event counter, streamed so the guest can show the toast too
function rebChk(who){
  if(gameMode!=='keepaway' || (ball.rebCD||0)>0) return;
  if(ball.shooter===who && ball.wallBounce && !ball.oppTouch){
    if(who==='p') possP+=3; else possT+=3;
    ball.wallBounce=false; ball.rebCD=240; rebSeq++; rebLastSide=who;   // ~4s cooldown so it can't be farmed
    showToast('🎯 REBOUND +3s!', who==='p'?'#69db7c':'#ff8787');
  }
}
function updatePossession(){
  if(ball.rebCD>0) ball.rebCD--;                    // tick the rebound-bonus cooldown
  if(ball.netSide){ ball.owner=null; return; }      // caught in net — leave it
  if(ball.kickLock>0){ball.kickLock--; ball.owner=null; return;}
  const dp=Math.hypot(ball.x-players.p.x, ball.y-players.p.y);
  const dt=oppActive?Math.hypot(ball.x-players.t.x, ball.y-players.t.y):1e9;
  const capP=grabCap(players.p), capT=oppActive?grabCap(players.t):0, cur=ball.owner;
  if(cur){
    const cd=cur==='p'?dp:dt, od=cur==='p'?dt:dp;
    const capCur=cur==='p'?capP:capT, capOpp=cur==='p'?capT:capP;
    if(ball.stealCD>0) ball.stealCD--;                     // tick the steal-contest cooldown
    if(cd>capCur+8){ ball.owner=null; }                    // carrier overextended -> ball comes loose (unchanged)
    // STEAL = a CONTEST, not an auto-strip. Boxes are IDENTICAL (grabCap); when the defender's box overlaps a
    // dribbling carrier, defense-vs-dribbling decides who wins, gated by a cooldown so it isn't spammable.
    else if(oppActive && od<capOpp && (ball.stealCD||0)<=0){
      const opp=(cur==='p'?'t':'p'), carrier=players[cur], defender=players[opp];
      const gap=(defender.defense||5)-(carrier.dribble||5);                 // + = defender favoured, - = carrier favoured
      const p=clamp(STEAL_BASE + gap*STEAL_WEIGHT, STEAL_MIN, STEAL_MAX);
      const stolen=Math.random()<p;
      recordContest(cur, opp, stolen);                                      // BUILD 2: observe-only (one pressure event -> carrier dribble + defender tackle)
      if(stolen){                                                          // defender wins the contest
        if(opp!==ball.shooter) ball.oppTouch=true;
        sfxGrunt(carrier.char); ball.owner=opp; ball.stealCD=STEAL_COOLDOWN;
      }else ball.stealCD=STEAL_TRY_GAP;                                     // failed -> brief gap before the next attempt
    }
  }else{
    if(dp<capP && dp<=dt){ ball.owner='p'; rebChk('p'); }
    else if(oppActive && dt<capT){ ball.owner='t'; rebChk('t'); }
  }
}
// players are solid — separate them so they can't overlap
function separatePlayers(){
  if(!oppActive)return;
  const a=players.p, b=players.t, min=PLAYER_R*2;
  const dx=b.x-a.x, dy=b.y-a.y; let d=Math.hypot(dx,dy);
  if(d<min){
    d=d||0.01; const nx=dx/d, ny=dy/d, ov=(min-d)/2;
    a.x-=nx*ov; a.y-=ny*ov; b.x+=nx*ov; b.y+=ny*ov;
    confineRound(a,PLAYER_R); confineRound(b,PLAYER_R);
    const rel=(b.vx-a.vx)*nx+(b.vy-a.vy)*ny;
    if(rel<0){ a.vx+=nx*rel*0.5; a.vy+=ny*rel*0.5; b.vx-=nx*rel*0.5; b.vy-=ny*rel*0.5; }
  }
}
function glueBall(){
  const pl=players[ball.owner];
  const hold=PLAYER_R+BALL_R-6;
  const hx=pl.x+Math.cos(pl.aim)*hold, hy=pl.y+Math.sin(pl.aim)*hold;
  const px=ball.x, py=ball.y;
  const drb=(pl.dribble!=null?pl.dribble:5);   // higher dribbling = tighter glue (harder to knock loose)
  const GRAB=DRIBBLE_GLUE_MIN + (drb/20)*(DRIBBLE_GLUE_MAX-DRIBBLE_GLUE_MIN);   // dribble is /20 now (b74)
  ball.x+=(hx-ball.x)*GRAB; ball.y+=(hy-ball.y)*GRAB;
  ball.vx=ball.x-px; ball.vy=ball.y-py;
  ball.x=clamp(ball.x,FIELD.l+BALL_R,FIELD.r-BALL_R); // no scoring while dribbling — kick it in
  ball.y=clamp(ball.y,FIELD.t+BALL_R,FIELD.b-BALL_R);
  cornerClampBall();
}

// ball vs player collision (loose ball only)
function ballPlayer(pl){
  const dx=ball.x-pl.x, dy=ball.y-pl.y; let d=Math.hypot(dx,dy);
  const min=PLAYER_R+BALL_R;
  if(d<min){
    if(pl.who!==ball.shooter) ball.oppTouch=true;   // opponent got a touch -> no rebound bonus
    d=d||0.01; const nx=dx/d, ny=dy/d, overlap=min-d;
    ball.x+=nx*overlap; ball.y+=ny*overlap;
    const dot=ball.vx*nx+ball.vy*ny;
    ball.vx-=2*dot*nx*0.6; ball.vy-=2*dot*ny*0.6;
    ball.vx+=pl.vx*0.45+nx*2.2; ball.vy+=pl.vy*0.45+ny*2.2;
  }
}
function ballWalls(){
  // if already in the net, stay caught
  if(ball.netSide){ netPhysics(ball.netSide); return; }
  if(ball.y<FIELD.t+BALL_R){ball.y=FIELD.t+BALL_R; if(ball.vy<0)ball.vy*=-0.86;}
  if(ball.y>FIELD.b-BALL_R){ball.y=FIELD.b-BALL_R; if(ball.vy>0)ball.vy*=-0.86;}
  const inMouth=(ball.y>GY0&&ball.y<GY1);
  if(ball.x<FIELD.l+BALL_R){
    if(inMouth && ball.x<FIELD.l){ ball.netSide='L'; scoreGoal('t'); netPhysics('L'); return; }
    if(!inMouth){ball.x=FIELD.l+BALL_R; if(ball.vx<0)ball.vx*=-0.86; if(Math.hypot(ball.x-(ball.kickX||0),ball.y-(ball.kickY||0))>220) ball.wallBounce=true;}  // a real driven shot off the goal frame
  }
  if(ball.x>FIELD.r-BALL_R){
    if(inMouth && ball.x>FIELD.r){ ball.netSide='R'; scoreGoal('p'); netPhysics('R'); return; }
    if(!inMouth){ball.x=FIELD.r-BALL_R; if(ball.vx>0)ball.vx*=-0.86; if(Math.hypot(ball.x-(ball.kickX||0),ball.y-(ball.kickY||0))>220) ball.wallBounce=true;}  // a real driven shot off the goal frame
  }
}
// catch the ball in the net: soft, absorbing, never bounces back onto the pitch
function netPhysics(side){
  const lineX = side==='L'? FIELD.l : FIELD.r;
  const backX = side==='L'? FIELD.l-GOAL_DEPTH+BALL_R : FIELD.r+GOAL_DEPTH-BALL_R;
  if(side==='L'){
    if(ball.x>lineX){ball.x=lineX;}                 // can't roll back out the front
    if(ball.x<backX){ball.x=backX; if(ball.vx<0)ball.vx*=-0.18;}
  }else{
    if(ball.x<lineX){ball.x=lineX;}
    if(ball.x>backX){ball.x=backX; if(ball.vx>0)ball.vx*=-0.18;}
  }
  if(ball.y<GY0+BALL_R){ball.y=GY0+BALL_R; if(ball.vy<0)ball.vy*=-0.2;}
  if(ball.y>GY1-BALL_R){ball.y=GY1-BALL_R; if(ball.vy>0)ball.vy*=-0.2;}
  ball.vx*=0.7; ball.vy*=0.7;                        // net absorbs energy
}
function stepBall(){
  ball.x+=ball.vx*motionScale; ball.y+=ball.vy*motionScale;
  ball.vx*=0.985; ball.vy*=0.985;
  ballWalls(); cornerClampBall();
  const sp=Math.hypot(ball.vx,ball.vy); if(sp>20){ball.vx=ball.vx/sp*20;ball.vy=ball.vy/sp*20;}
}

function scoreGoal(who){
  if(goalLock>0)return;
  goalLock=70;
  if(gameMode==='keepaway'){ showToast('LOOSE BALL!','#9bf6a8'); setTimeout(()=>reset(),650); return; }
  if(slowmoGateOk()) slowmoT=Math.max(slowmoT, GOAL_SLOWMO_MS/1000);   // gated decider: slow-mo the explosion too (margin read PRE-increment)
  score[who]++; updateHUD();
  recordGoalStat(who);   // BUILD 2: per-character goals scored / conceded / own-goal (observe-only)
  showToast('GOAL!', who==='p'?'#69db7c':'#ff8787');
  { const el=document.getElementById('toast'); if(el){ el.classList.remove('slam'); void el.offsetWidth; el.classList.add('slam'); } }   // slam-in
  const fxSide = ball.netSide || (who==='t'?'L':'R');     // 'L'/'R' = which goal was scored in
  goalSeq++; goalFxSide=fxSide; triggerGoalFx(fxSide);    // explosion now (host/local); the guest detonates from the streamed goalSeq
  sfxCheer();
  if(golden){ setTimeout(()=>endGame(who),750); return; }   // sudden death
  setTimeout(()=>reset(who==='p'?'t':'p'),650);              // conceder gets ball closer
}
// ---- half-time pause (5s frozen break, then resume where they left off) ----
let htTimer=null, htCountTimer=null;
function showHalftime(){
  const ov=$('halftimeScreen'); if(!ov) return;
  ov.classList.remove('hide');
  let n=5; const num=$('htCount'); if(num) num.textContent=n;
  clearInterval(htCountTimer);
  htCountTimer=setInterval(()=>{ n--; if(num) num.textContent=(n>0?n:0); if(n<=0) clearInterval(htCountTimer); }, 1000);
}
function hideHalftime(){ const ov=$('halftimeScreen'); if(ov) ov.classList.add('hide'); clearInterval(htCountTimer); }
function onTimeUp(){
  if(gameMode==='keepaway'){ endGame(possP>=possT?'p':'t'); return; }   // single 1:30 period, no half-time
  if(half===1){                       // first half done -> 5s frozen half-time, then 2nd-half kickoff
    halftime=true; timeLeft=0; updateHUD();
    setMeta('HALF TIME'); showHalftime();
    // the loop keeps streaming snapshots with ht=1 so the guest freezes + shows the screen too
    clearTimeout(htTimer);
    htTimer=setTimeout(()=>{
      half=2; halftime=false; timeLeft=MATCH_TIME;
      reset();                        // 2nd half: ball back to centre, players to their starting spots
      setMeta(halfLabel()); updateHUD(); hideHalftime();
    }, 5000);
    return;
  }
  if(score.p===score.t){ golden=true; setMeta('GOLDEN GOAL'); showToast('GOLDEN GOAL','#ffd43b'); updateHUD(); }
  else endGame(score.p>score.t?'p':'t');
}

function showToast(txt,col){const el=document.getElementById('toast');
  el.textContent=txt; el.style.color='#fff';
  el.style.textShadow=`0 4px 0 #000,0 0 34px ${col}`; toastT=60;}
// b85: juiced yellow/red card flash (like real football) — a card slams onto the screen, holds, then fades.
function showCard(type,name){
  const ov=$('cardFlash'), rect=$('cardRect'), msg=$('cardMsg'); if(!ov) return;
  rect.className = 'card-'+type;
  msg.textContent = (type==='red'?'RED CARD':'YELLOW CARD') + ' · ' + name + (type==='red'?' SENT OFF':'');
  ov.classList.remove('hide','show'); void ov.offsetWidth; ov.classList.add('show');   // restart the CSS animation
  clearTimeout(cardFxTimer);
  cardFxTimer=setTimeout(()=>{ ov.classList.add('hide'); ov.classList.remove('show'); }, type==='red'?2600:1700);
  try{ if(type==='red') sfxBoom(); else sfxKick(); }catch(e){}
}

function endGame(who){
  state='win';
  if(netRole==='host') sendState({st:'win', win:who});   // tell the guest the match is over
  if(ranked && account) recordResult(who==='p');   // endGame is always the local (left) player's perspective
  commitMatchStats(who);   // BUILD 2: per-character record — host commits its own + relays the guest its own (no double-count)
  document.getElementById('winScreen').classList.remove('hide');
  const pName = players? STATS[players.p.char].name : 'PEPE';
  const tName = players? STATS[players.t.char].name : 'TRUMPE';
  const n=document.getElementById('winName');
  n.textContent= who==='p'?pName:tName;
  n.style.color= who==='p'?'#69db7c':'#ff8787';
  const msg=document.getElementById('winMsg');
  if(ranked && account){
    msg.textContent=(who==='p'?'You win! ':'You lost. ')+account.wins+'W · '+account.losses+'L';
  } else if(gameMode==='keepaway'){
    msg.textContent=(who==='p'?pName:tName)+' held it longest — '+Math.floor(Math.max(possP,possT))+'s vs '+Math.floor(Math.min(possP,possT))+'s ⏱️';
  } else {
    msg.textContent=(who==='p'?pName:tName)+' wins the Based Cup! 🏆';
  }
  setupEndScreen();
  awardEndOfMatch(who==='p');
}

// ---- Render ----
function rr(x,y,w,h,r){r=Math.min(r,w/2,h/2);ctx.beginPath();
  ctx.moveTo(x+r,y);ctx.arcTo(x+w,y,x+w,y+h,r);ctx.arcTo(x+w,y+h,x,y+h,r);
  ctx.arcTo(x,y+h,x,y,r);ctx.arcTo(x,y,x+w,y,r);ctx.closePath();}
let _embers=null;
function drawHero(img, cx, baseY, dir, gr, gg, gb, scale, noClamp){
  if(!img||!img.complete||!img.width) return;
  scale=scale||1;
  // sprites are now head-frames (face centred, chin at 84%); bump the size and anchor by the chin
  const h=H*0.74*scale, w=h*(img.width/img.height);
  if(!noClamp){ const margin=12;                    // never let a hero crop off-screen (menu only)
    if(cx-w/2<margin) cx=margin+w/2;
    if(cx+w/2>W-margin) cx=W-margin-w/2; }
  const cy=baseY-(1-FACE_CYF)*h;                     // face centre (the glow / pool focus on the head)
  // spotlight pool on the floor
  const pg=ctx.createRadialGradient(cx,baseY,4,cx,baseY,w*0.6);
  pg.addColorStop(0,'rgba('+gr+','+gg+','+gb+',.30)'); pg.addColorStop(1,'rgba('+gr+','+gg+','+gb+',0)');
  ctx.fillStyle=pg; ctx.beginPath(); ctx.ellipse(cx,baseY,w*0.5,h*0.10,0,0,7); ctx.fill();
  // soft glow BEHIND the head (radial halo — no rectangular crop lines at the PNG border)
  const bgl=ctx.createRadialGradient(cx,cy,4,cx,cy,h*0.4);
  bgl.addColorStop(0,'rgba('+gr+','+gg+','+gb+',.24)'); bgl.addColorStop(1,'rgba('+gr+','+gg+','+gb+',0)');
  ctx.fillStyle=bgl; ctx.beginPath(); ctx.ellipse(cx,cy,w*0.46,h*0.4,0,0,7); ctx.fill();
  // hero — drawn with NO shadow so the character edges stay clean; chin ~ on the ground line
  ctx.save(); ctx.translate(cx,baseY); ctx.scale(dir,1);
  ctx.drawImage(img, -w/2, -CHIN_FRAC_DRAW*h, w, h);
  ctx.restore();
}
let titleSim=null;
function drawTitleScene(){
  const now=performance.now(), t=now/1000;
  if(!titleSim) titleSim={ t:now, x:-W*0.25, lap:0 };
  let dt=Math.min(0.05,(now-titleSim.t)/1000); titleSim.t=now;
  const s=titleSim, groundY=H*0.74;
  // even lap: run left->right; odd lap: run right->left. Roles + direction flip each lap, looping.
  const runRight = (s.lap%2===0);
  s.x += (runRight?1:-1)*W*0.40*dt;
  if(runRight && s.x > W*1.25){ s.lap++; s.x = W*1.25; }
  else if(!runRight && s.x < -W*0.25){ s.lap++; s.x = -W*0.25; }
  const dirSign = runRight?1:-1;
  const leadX=s.x, chaseX=s.x - dirSign*W*0.20, ballX=s.x + dirSign*W*0.085;
  const leadHop=Math.abs(Math.sin(t*12))*11, chaseHop=Math.abs(Math.sin(t*12+1.4))*12;

  // night sky
  let sky=ctx.createLinearGradient(0,0,0,groundY);
  sky.addColorStop(0,'#0a1622'); sky.addColorStop(1,'#0c2a1d');
  ctx.fillStyle=sky; ctx.fillRect(0,0,W,groundY);
  // pitch
  let pit=ctx.createLinearGradient(0,groundY,0,H);
  pit.addColorStop(0,'#1f7a45'); pit.addColorStop(1,'#0c3a20');
  ctx.fillStyle=pit; ctx.fillRect(0,groundY,W,H-groundY);
  ctx.save(); ctx.beginPath(); ctx.rect(0,groundY,W,H-groundY); ctx.clip();
  for(let i=0;i<14;i++){ ctx.fillStyle=i%2?'rgba(255,255,255,.04)':'rgba(0,0,0,.06)'; ctx.fillRect(i*W/14,groundY,W/14,H-groundY); }
  ctx.strokeStyle='rgba(233,255,240,.18)'; ctx.lineWidth=3;
  ctx.beginPath(); ctx.moveTo(W/2,groundY); ctx.lineTo(W/2,H); ctx.stroke();
  ctx.beginPath(); ctx.arc(W/2,groundY+(H-groundY)*0.5,58,Math.PI,2*Math.PI); ctx.stroke();
  ctx.restore();
  // centre glow + stadium beams
  let rg=ctx.createRadialGradient(W/2,H*0.40,30,W/2,H*0.46,W*0.62);
  rg.addColorStop(0,'rgba(105,219,124,.16)'); rg.addColorStop(1,'rgba(0,0,0,0)');
  ctx.fillStyle=rg; ctx.fillRect(0,0,W,H);
  ctx.save(); ctx.globalCompositeOperation='lighter';
  for(let i=0;i<6;i++){ const x=W*(0.08+0.17*i), sway=Math.sin(t*0.5+i*1.3)*26;
    const lg=ctx.createLinearGradient(x,0,x+sway,H*0.9);
    lg.addColorStop(0,'rgba(170,225,255,.06)'); lg.addColorStop(1,'rgba(170,225,255,0)');
    ctx.fillStyle=lg; ctx.beginPath(); ctx.moveTo(x-26,0); ctx.lineTo(x+26,0); ctx.lineTo(x+100+sway,H); ctx.lineTo(x-100+sway,H); ctx.closePath(); ctx.fill(); }
  ctx.restore();
  // embers
  if(!_embers){ _embers=[]; for(let i=0;i<22;i++)_embers.push({x:Math.random()*W,y:Math.random()*H,s:0.4+Math.random()*1.2,r:1+Math.random()*2}); }
  ctx.save(); ctx.globalCompositeOperation='lighter';
  _embers.forEach(e=>{ e.y-=e.s; e.x+=Math.sin((t+e.r)*0.6)*0.3; if(e.y<-5){e.y=H+5;e.x=Math.random()*W;}
    ctx.fillStyle='rgba(150,240,170,'+(0.08+0.08*Math.sin(t*2+e.r)).toFixed(3)+')';
    ctx.beginPath(); ctx.arc(e.x,e.y,e.r,0,7); ctx.fill(); });
  ctx.restore();
  // speed lines behind the chaser (cartoon dash)
  ctx.strokeStyle='rgba(255,255,255,.10)'; ctx.lineWidth=3;
  for(let i=0;i<5;i++){ const ly=groundY-40-i*26, len=40+i*10;
    ctx.beginPath(); ctx.moveTo(chaseX-110,ly); ctx.lineTo(chaseX-110+len,ly); ctx.stroke(); }
  // ---- the chase: bigger rolling ball, leader dribbling, chaser behind ----
  const ballY=groundY-10-Math.abs(Math.sin(t*10))*12;
  ctx.fillStyle='rgba(0,0,0,.32)'; ctx.beginPath(); ctx.ellipse(ballX,groundY+6,24,8,0,0,7); ctx.fill();
  ball.vx=dirSign*W*0.4; ball.vy=0;                  // make the title ball roll the way it travels
  ctx.save(); ctx.translate(ballX,ballY); ctx.scale(2.1,2.1); ctx.translate(-ballX,-ballY); drawBall(ballX,ballY); ctx.restore();
  // even lap: Pepe leads with the ball (Trumpe chasing); odd lap: Trumpe leads (Pepe chasing)
  const pepeLeads = (s.lap%2===0);
  const leadImg=pepeLeads?imgP:imgT, chaseImg=pepeLeads?imgT:imgP;
  const lg=pepeLeads?[105,219,124]:[255,135,135], cg=pepeLeads?[255,135,135]:[105,219,124];
  // face the way they run: Pepe faces right at dir=1, Trumpe's art is mirrored so faces right at dir=-1
  const leadDir  = pepeLeads ? (runRight?1:-1) : (runRight?-1:1);
  const chaseDir = pepeLeads ? (runRight?-1:1) : (runRight?1:-1);
  drawHero(leadImg,  leadX,  groundY-leadHop,  leadDir,  lg[0],lg[1],lg[2], 0.60, true);
  drawHero(chaseImg, chaseX, groundY-chaseHop, chaseDir, cg[0],cg[1],cg[2], 0.60, true);
  // vignette
  let vg=ctx.createRadialGradient(W/2,H/2,H*0.34,W/2,H/2,H*0.82);
  vg.addColorStop(0,'rgba(0,0,0,0)'); vg.addColorStop(1,'rgba(0,0,0,.6)');
  ctx.fillStyle=vg; ctx.fillRect(0,0,W,H);
}
// ---- Goal explosion: blast the two heads + ball AWAY from the scored-in goal (visual only) ----
// slow-mo gate: a dramatic decider — 2nd half, last 20s, pre-goal score margin <= 1 (or FORCE for feel-testing)
function slowmoGateOk(){
  if(FORCE_GOAL_SLOWMO) return true;
  return gameMode==='goals' && half===2 && timeLeft<=SLOWMO_LAST_SECS && Math.abs(score.p-score.t)<=SLOWMO_MARGIN;
}
// Pass 2: true only if the DEFENDER physically can't reach the ball's path before it crosses the line (unstoppable).
function shotIsPlayerUnstoppable(side){
  if(!players || !ball) return false;
  const lineX = side==='L' ? FIELD.l : FIELD.r, vx=ball.vx;
  if((side==='L' && vx>=-0.5) || (side==='R' && vx<=0.5)) return false;         // not actually heading at this goal
  const tCross = (lineX - ball.x)/vx;                                           // frames until it reaches the goal line
  if(tCross<=0 || tCross>200) return false;                                     // behind it / too slow to matter
  const yAtLine = ball.y + ball.vy*tCross;                                      // where the path exits the line
  if(yAtLine < GY0-SLOWMO_POST_GRACE || yAtLine > GY1+SLOWMO_POST_GRACE) return false;  // clear miss -> wall/post stops it
  const def = (side==='L') ? players.p : players.t;                             // L goal defended by p, R goal by t
  if(!def) return false;
  const cap = grabCap(def);                                                     // identical reach (48)
  const maxSpd = ((def.maxOff||5) + DEF_CLOSE_BONUS*(def.defense||5)) * SLOWMO_DEF_SPEED_K;   // off-ball + closing bonus
  let canStop=false, best=1e9;
  for(let i=0;i<=10;i++){                                                       // sample the path; can the defender beat the ball to ANY point?
    const t=tCross*i/10, px=ball.x+vx*t, py=ball.y+ball.vy*t;
    const need=Math.hypot(def.x-px, def.y-py)-cap;                             // distance the defender must still close
    best=Math.min(best, need - maxSpd*t);
    if(need <= maxSpd*t - SLOWMO_REACH_MARGIN){ canStop=true; break; }         // reaches it (with margin) -> stoppable
  }
  if(SLOWMO_DEBUG) console.log('[slowmo] side',side,'tCross',tCross.toFixed(1),'yAtLine',Math.round(yAtLine),'defMaxSpd',maxSpd.toFixed(2),'closeGap',best.toFixed(1),'->',canStop?'STOPPABLE':'UNSTOPPABLE');
  return !canStop;                                                              // nobody can intervene -> unstoppable
}
// arm slow-mo as a fast, goal-bound free shot ENTERS the zone in front of either mouth (host/local only)
function maybeArmSlowmo(){
  if(!ball || ball.owner || ball.netSide) return;                  // no free shot in flight
  if(!(ball.y>GY0 && ball.y<GY1)) return;                          // must be on target (inside the mouth)
  const nearL = ball.x < FIELD.l+SLOWMO_ZONE && ball.vx < -SLOWMO_BALL_SPEED;   // screaming into the LEFT goal
  const nearR = ball.x > FIELD.r-SLOWMO_ZONE && ball.vx >  SLOWMO_BALL_SPEED;   // screaming into the RIGHT goal
  if((nearL||nearR) && slowmoGateOk()){
    const side = nearL ? 'L' : 'R';
    if(slowmoT<=0){                                  // decide ONCE as the shot ENTERS the zone (reach + framing); never flip mid-slow-mo
      if(!FORCE_GOAL_SLOWMO && !shotIsPlayerUnstoppable(side)) return;          // Pass 2: only arm if the defender can't reach it
      slowmoCamSide = side;                          // the goal being scored on
      const strikeX = (ball.kickX!=null) ? ball.kickX : ball.x;          // where the shot was STRUCK from (set in tryKick)
      // short-range = struck INSIDE the opponent's half (the half holding the target goal) -> LOCK on that goal.
      // long-range  = struck from own half / beyond halfway -> FOLLOW the ball the whole way in.
      const shortRange = slowmoCamSide==='R' ? (strikeX > W/2) : (strikeX < W/2);
      slowmoCamMode = shortRange ? 'goal' : 'ball';
    }
    slowmoT=Math.max(slowmoT, GOAL_SLOWMO_MS/1000);  // keep topped while in the zone -> whole crossing stays slow
  }
}
function isSlowmo(){ return netRole==='guest' ? netSlowmo : slowmoT>0; }   // guest follows the host's streamed flag
function triggerGoalFx(side){
  if(!players||!ball) return;
  const gx = side==='L' ? FIELD.l : FIELD.r, gy=H/2;        // the goal mouth that was scored in
  const objs=[];
  function add(o,img,isBall){
    const dx=o.x-gx, dy=o.y-gy, d=Math.hypot(dx,dy)||1, dir=Math.atan2(dy,dx);
    const prox=clamp(1 - d/(W*0.85), 0.18, 1);              // closer to the goal => harder blast (scaled by distance)
    const sp=9 + prox*18;
    objs.push({ img, isBall, x:o.x, y:o.y, vx:Math.cos(dir)*sp + (Math.random()-.5)*3,
      vy:Math.sin(dir)*sp - (4+prox*6), rot:0, vrot:(Math.random()-.5)*0.45, face:(o.face||1) });
  }
  add(players.p, imgFor(players.p.char), false);
  if(oppActive) add(players.t, imgFor(players.t.char), false);
  add(ball, null, true);
  const sparks=[], out=(side==='L'?1:-1);
  for(let i=0;i<40;i++){ const a=Math.random()*Math.PI - Math.PI/2, s=5+Math.random()*16;   // fan outward into the field
    sparks.push({ x:gx, y:gy+(Math.random()-.5)*GOAL_H*0.9, vx:out*(Math.cos(a)*s+4), vy:Math.sin(a)*s, life:1,
      col: Math.random()<0.5?'#ffd43b':(Math.random()<0.5?'#fff':(side==='L'?'#69db7c':'#ff8787')) }); }
  goalFx={ t:0, dur:GOAL_FX_MS/1000, side, gx, gy, objs, sparks, slowT:GOAL_SLOWMO_MS/1000 };
  shakeAmp=GOAL_SHAKE;
  try{ sfxBoom(); }catch(e){}
}
function updateGoalFx(dt){
  if(shakeAmp>0){ shakeAmp*=Math.pow(0.02,dt); if(shakeAmp<0.5) shakeAmp=0; }   // decay the screen shake
  if(!goalFx) return;
  goalFx.t+=dt; const f=dt*60, grav=0.5*f;
  for(const o of goalFx.objs){ o.x+=o.vx*f; o.y+=o.vy*f; o.vy+=grav; o.rot+=o.vrot*f; }
  for(const s of goalFx.sparks){ s.x+=s.vx*f; s.y+=s.vy*f; s.vy+=grav*0.8; s.vx*=Math.pow(0.97,f); s.life-=dt/0.5; }
  if(goalFx.t>=goalFx.dur) goalFx=null;
}
function drawHeadAt(img,x,y,rot,face,alpha){
  if(!(img&&img.complete&&img.naturalWidth)) return;
  const R=PLAYER_R, iw=img.naturalWidth, ih=img.naturalHeight, s=(R*FACE_FIT)/(iw*FACE_RF);
  ctx.save(); ctx.globalAlpha=alpha; ctx.translate(x,y); ctx.rotate(rot); if(face<0)ctx.scale(-1,1);
  ctx.drawImage(img,-iw*0.5*s,-ih*FACE_CYF*s,iw*s,ih*s); ctx.restore();
}
function drawGoalFx(){
  const fx=goalFx; if(!fx) return; const p=fx.t/fx.dur;
  ctx.save();
  // expanding shockwave ring + bright flash at the goal mouth
  ctx.globalAlpha=Math.max(0,1-p*1.3)*0.85; ctx.strokeStyle= fx.side==='L'?'#69db7c':'#ff8787'; ctx.lineWidth=10*(1-p)+2;
  ctx.beginPath(); ctx.arc(fx.gx,fx.gy,20+p*440,0,7); ctx.stroke();
  const fl=Math.max(0,1-p*3);
  if(fl>0){ const gr=ctx.createRadialGradient(fx.gx,fx.gy,4,fx.gx,fx.gy,280);
    gr.addColorStop(0,'rgba(255,255,255,'+(0.9*fl)+')'); gr.addColorStop(1,'rgba(255,255,255,0)');
    ctx.globalAlpha=1; ctx.fillStyle=gr; ctx.beginPath(); ctx.arc(fx.gx,fx.gy,280,0,7); ctx.fill(); }
  // sparks
  for(const s of fx.sparks){ if(s.life<=0) continue; ctx.globalAlpha=Math.max(0,s.life); ctx.fillStyle=s.col;
    ctx.beginPath(); ctx.arc(s.x,s.y,3.2*s.life+1,0,7); ctx.fill(); }
  ctx.globalAlpha=1; ctx.restore();
  // debris: the two heads + ball flying out, fading near the end
  const fade = p>0.7 ? Math.max(0,1-(p-0.7)/0.3) : 1;
  for(const o of fx.objs){
    if(o.isBall){ ctx.save(); ctx.globalAlpha=fade; ctx.translate(o.x,o.y); ctx.rotate(o.rot);
      ctx.beginPath();ctx.arc(0,0,BALL_R,0,7);ctx.fillStyle='#fff';ctx.fill(); ctx.lineWidth=2;ctx.strokeStyle='#1b1b1b';ctx.stroke();
      ctx.fillStyle='#161616';ctx.beginPath();ctx.arc(0,-BALL_R*0.3,BALL_R*0.32,0,7);ctx.fill(); ctx.restore(); }
    else drawHeadAt(o.img,o.x,o.y,o.rot,o.face,fade);
  }
}
function draw(){
  // menu / title / lobby screens get the cinematic backdrop; matches show the pitch
  if(state!=='play' && state!=='win' && state!=='paused'){ drawTitleScene(); return; }
  // cinematic slow-mo camera: FOLLOW the ball (long-range shot) or LOCK on the target goal (short-range), decided at arm-time
  let _fx=W/2, _fy=H/2;
  if(isSlowmo()){
    const camGoal = (netRole==='guest') ? (netCamMode==='goal') : (slowmoCamMode==='goal');
    const camSide = (netRole==='guest') ? netCamSide : slowmoCamSide;
    if(goalFx){ _fx=goalFx.gx; _fy=goalFx.gy; }                          // during the blast, frame the goal where it happened
    else if(camGoal){ _fx=(camSide==='L'?FIELD.l:FIELD.r); _fy=H/2; }    // short-range: locked on the target goal
    else if(ball){ _fx=ball.x; _fy=ball.y; }                             // long-range: follow the ball all the way in
  }
  camZoom   += ((isSlowmo()?SLOWMO_ZOOM:1) - camZoom)*SLOWMO_ZOOM_EASE;
  camFocusX += (_fx-camFocusX)*SLOWMO_FOLLOW_EASE; camFocusY += (_fy-camFocusY)*SLOWMO_FOLLOW_EASE;
  { const hw=W/(2*camZoom), hh=H/(2*camZoom); camFocusX=clamp(camFocusX,hw,W-hw); camFocusY=clamp(camFocusY,hh,H-hh); }   // keep the view on-field
  ctx.save();
  ctx.translate(camFocusX,camFocusY); ctx.scale(camZoom,camZoom); ctx.translate(-camFocusX,-camFocusY);   // zoom toward focus
  if(shakeAmp>0.5){ ctx.translate((Math.random()-.5)*shakeAmp,(Math.random()-.5)*shakeAmp); }   // screen shake (goal juice)
  const fw=W-2*PAD, fh=H-2*PAD;
  // pitch (rounded corners) — clip stripes to the rounded field
  ctx.save(); rr(FIELD.l,FIELD.t,fw,fh,CORNER); ctx.clip();
  for(let i=0;i<12;i++){
    ctx.fillStyle=i%2? '#2f9e44':'#34a949';
    ctx.fillRect(PAD+i*fw/12, PAD, fw/12, fh);
  }
  ctx.restore();
  ctx.strokeStyle='rgba(233,255,240,.85)'; ctx.lineWidth=3;
  rr(FIELD.l,FIELD.t,fw,fh,CORNER); ctx.stroke();
  // halfway line + circle
  ctx.beginPath();ctx.moveTo(W/2,FIELD.t);ctx.lineTo(W/2,FIELD.b);ctx.stroke();
  ctx.beginPath();ctx.arc(W/2,H/2,70,0,7);ctx.stroke();
  ctx.beginPath();ctx.arc(W/2,H/2,4,0,7);ctx.fillStyle='rgba(233,255,240,.85)';ctx.fill();
  // penalty boxes
  const bx=130, byT=H/2-140, byB=H/2+140;
  ctx.strokeRect(FIELD.l,byT,bx,byB-byT);
  ctx.strokeRect(FIELD.r-bx,byT,bx,byB-byT);
  // goals
  drawGoal(FIELD.l,true,'#69db7c'); drawGoal(FIELD.r,false,'#ff8787');

  if(goalFx){
    drawGoalFx();                          // GOAL EXPLOSION — blast debris + flash + sparks replace the frozen heads/ball
  } else {
    // ball shadow + ball
    ctx.fillStyle='rgba(0,0,0,.28)';
    ctx.beginPath();ctx.ellipse(ball.x,ball.y+10,BALL_R,BALL_R*0.5,0,0,7);ctx.fill();
    drawBall(ball.x,ball.y);
    // players
    if(oppActive) drawPlayer(players.t,imgFor(players.t.char),'#ff8787');
    drawPlayer(players.p,imgFor(players.p.char),'#69db7c');
    // aim arrows for human-controlled players — NOT in keep-away (it's a possession mode, no shooting; arrow is just noise)
    if(gameMode!=='keepaway'){
      drawAim(players.p,'#9bf6a8', ball.owner==='p');
      if(oppActive && (mode==='2p'||netRole)) drawAim(players.t,'#ffb3b3', ball.owner==='t');
    }
  }
  ctx.restore();   // end screen shake

  // toast fade
  const el=document.getElementById('toast');
  if(toastT>0){toastT--; el.style.opacity=Math.min(1,toastT/12);}
  else el.style.opacity=0;
}
function drawGoal(x,left,col){
  const depth=GOAL_DEPTH, dir=left?-1:1, outX=left?FIELD.l-depth:FIELD.r, backX=x+dir*depth;
  ctx.save();
  // net backing
  ctx.fillStyle='rgba(255,255,255,.12)';
  ctx.fillRect(outX, GY0, depth, GOAL_H);
  // net mesh
  ctx.strokeStyle='rgba(255,255,255,.38)';ctx.lineWidth=1;
  for(let i=0;i<=depth;i+=6){ctx.beginPath();ctx.moveTo(x+dir*i,GY0);ctx.lineTo(x+dir*i,GY1);ctx.stroke();}
  for(let yy=GY0;yy<=GY1;yy+=11){ctx.beginPath();ctx.moveTo(x,yy);ctx.lineTo(backX,yy);ctx.stroke();}
  // ONE continuous goal frame: front-top post -> top bar -> back bar -> bottom bar -> front-bottom post
  ctx.lineJoin='round'; ctx.lineCap='round';
  ctx.strokeStyle='rgba(0,0,0,.35)'; ctx.lineWidth=10;   // subtle outline so it reads on grass
  framePath(x,backX); ctx.stroke();
  ctx.strokeStyle='#fdfdfd'; ctx.lineWidth=6;
  framePath(x,backX); ctx.stroke();
  // coloured goal line joining the two front posts (the mouth)
  ctx.strokeStyle=col; ctx.lineWidth=4;
  ctx.beginPath();ctx.moveTo(x,GY0);ctx.lineTo(x,GY1);ctx.stroke();
  ctx.restore();
}
function framePath(x,backX){
  ctx.beginPath();
  ctx.moveTo(x,GY0); ctx.lineTo(backX,GY0);     // front-top post + top bar
  ctx.lineTo(backX,GY1);                         // back bar
  ctx.lineTo(x,GY1);                             // bottom bar + front-bottom post
}
function drawBall(x,y){
  const sp=Math.hypot(ball.vx,ball.vy);
  ball.roll=(ball.roll||0) + sp/BALL_R;                 // accumulate roll with distance
  if(sp>0.4) ball.dir=Math.atan2(ball.vy,ball.vx);      // remember travel direction
  const dir=ball.dir||0;
  ctx.save();
  ctx.translate(x,y);
  // ball body
  ctx.beginPath();ctx.arc(0,0,BALL_R,0,7);ctx.fillStyle='#fff';ctx.fill();
  ctx.lineWidth=2;ctx.strokeStyle='#1b1b1b';ctx.stroke();
  // spots that roll across the face in the travel direction
  ctx.rotate(dir);
  ctx.beginPath();ctx.arc(0,0,BALL_R,0,7);ctx.clip();
  ctx.fillStyle='#161616';
  const SPOTS=[{py:0,po:0},{py:0.62,po:1.1},{py:-0.62,po:1.1},{py:0.62,po:-1.1},{py:-0.62,po:-1.1}];
  for(const s of SPOTS){
    const ph=ball.roll + s.po;
    const depth=Math.cos(ph);                            // >0 = on the visible face
    if(depth>0.04){
      const cx=Math.sin(ph)*BALL_R*0.74;                 // slides in travel direction
      const cy=s.py*BALL_R*0.62;
      const r=BALL_R*0.27*depth + BALL_R*0.04;
      ctx.globalAlpha=Math.min(1,depth+0.25);
      ctx.beginPath();ctx.ellipse(cx,cy,r,r*0.9,0,0,7);ctx.fill();
    }
  }
  ctx.globalAlpha=1;
  ctx.restore();
}
function drawAim(pl,col,hasBall){
  const a=pl.aim, base=Math.max(PLAYER_R, SPRITE_H*0.5)+12;  // clear the head sprite
  const r0=base, r1=base+(hasBall?26:18);
  const x0=pl.x+Math.cos(a)*r0, y0=pl.y+Math.sin(a)*r0;
  const x1=pl.x+Math.cos(a)*r1, y1=pl.y+Math.sin(a)*r1;
  ctx.save(); ctx.lineCap='round'; ctx.lineJoin='round';
  function head(size,c){ctx.fillStyle=c;ctx.beginPath();
    ctx.moveTo(x1+Math.cos(a)*size*0.6, y1+Math.sin(a)*size*0.6);
    ctx.lineTo(x1-Math.cos(a-0.55)*size, y1-Math.sin(a-0.55)*size);
    ctx.lineTo(x1-Math.cos(a+0.55)*size, y1-Math.sin(a+0.55)*size);
    ctx.closePath();ctx.fill();}
  // dark outline pass
  ctx.strokeStyle='rgba(0,0,0,.55)'; ctx.lineWidth=hasBall?11:9;
  ctx.beginPath();ctx.moveTo(x0,y0);ctx.lineTo(x1,y1);ctx.stroke();
  head(hasBall?19:16,'rgba(0,0,0,.55)');
  // colored pass
  ctx.globalAlpha=hasBall?1:0.85;
  ctx.strokeStyle=col; ctx.lineWidth=hasBall?6:5;
  ctx.beginPath();ctx.moveTo(x0,y0);ctx.lineTo(x1,y1);ctx.stroke();
  head(hasBall?15:12,col);
  ctx.restore();
}
function drawPlayer(pl,img,col){
  if(pl.out) return;                  // b85: a red-carded player has left the pitch (2v2 path; in 1v1 the match has ended)
  const R=PLAYER_R;
  // b85: lunge whoosh — a short motion streak behind a dashing player (visual only)
  if(pl.lunging>0){ const a=Math.atan2(pl.lvy,pl.lvx), len=R*2.2;
    ctx.save(); ctx.globalAlpha=0.32; ctx.strokeStyle=col; ctx.lineCap='round'; ctx.lineWidth=R*1.1;
    ctx.beginPath(); ctx.moveTo(pl.x-Math.cos(a)*len, pl.y-Math.sin(a)*len); ctx.lineTo(pl.x, pl.y); ctx.stroke(); ctx.restore(); }
  // soft team-coloured pool on the ground — the ONLY team marker now (no hard hitbox ring),
  // so same-character matchups stay readable while the collision itself is invisible.
  ctx.save();
  const pool=ctx.createRadialGradient(pl.x,pl.y+R*0.55,1,pl.x,pl.y+R*0.55,R*1.7);
  pool.addColorStop(0,col); pool.addColorStop(1,'rgba(0,0,0,0)');
  ctx.globalAlpha=0.42; ctx.fillStyle=pool;
  ctx.beginPath();ctx.ellipse(pl.x,pl.y+R*0.62,R*1.55,R*0.66,0,0,7);ctx.fill();
  ctx.restore();
  // soft drop shadow
  ctx.fillStyle='rgba(0,0,0,.26)';
  ctx.beginPath();ctx.ellipse(pl.x,pl.y+R*0.95,R*0.8,R*0.34,0,0,7);ctx.fill();
  // boost: a warm aura instead of a ring
  if(pl.boost>0.4){ ctx.save(); ctx.globalAlpha=0.55;
    const ba=ctx.createRadialGradient(pl.x,pl.y,R*0.6,pl.x,pl.y,R*2);
    ba.addColorStop(0,'rgba(255,212,59,0)'); ba.addColorStop(0.72,'rgba(255,212,59,.55)'); ba.addColorStop(1,'rgba(255,212,59,0)');
    ctx.fillStyle=ba; ctx.beginPath();ctx.arc(pl.x,pl.y,R*2,0,7);ctx.fill(); ctx.restore(); }
  // head — face CENTRED on the player, scaled so the face edge ≈ the (invisible) collision radius
  let headTop=pl.y-R*2;
  if(img.complete && img.naturalWidth){
    const iw=img.naturalWidth, ih=img.naturalHeight;
    const s=(R*FACE_FIT)/(iw*FACE_RF), w=iw*s, h=ih*s;
    headTop=pl.y - ih*FACE_CYF*s;
    ctx.save();
    ctx.translate(pl.x,pl.y);
    if(pl.face<0)ctx.scale(-1,1);
    ctx.drawImage(img,-iw*0.5*s,-ih*FACE_CYF*s,w,h);
    ctx.restore();
  }
  // charge / power bar above the head while winding up a kick
  if(pl.charging && pl.charge>0.02){
    const bw=46, bh=7, bx=pl.x-bw/2, by=headTop-12;
    ctx.fillStyle='rgba(0,0,0,.55)';
    roundRect(bx-2,by-2,bw+4,bh+4,4); ctx.fill();
    const c=pl.charge;
    ctx.fillStyle = c<0.5 ? '#ffd43b' : (c<0.85 ? '#ff9f43' : '#ff5252');
    roundRect(bx,by,bw*c,bh,3); ctx.fill();
    ctx.lineWidth=1.5; ctx.strokeStyle='rgba(255,255,255,.85)';
    roundRect(bx,by,bw,bh,3); ctx.stroke();
  }
}
function roundRect(x,y,w,h,r){ ctx.beginPath();
  ctx.moveTo(x+r,y); ctx.arcTo(x+w,y,x+w,y+h,r); ctx.arcTo(x+w,y+h,x,y+h,r);
  ctx.arcTo(x,y+h,x,y,r); ctx.arcTo(x,y,x+w,y,r); ctx.closePath(); }

// ---- Loop ----
let orientAcc=0;
function loop(ts){
  requestAnimationFrame(loop);
  const dt=Math.min(0.05,(ts-lastTs)/1000||0); lastTs=ts;
  if(IS_TOUCH){ orientAcc+=dt; if(orientAcc>=0.25){ orientAcc=0; checkOrient(); } }   // keep the rotate nudge in sync
  if(state==='play'){
    if(netRole==='guest'){
      // thin client: stream input (throttled), render the host's snapshot smoothly,
      // and locally predict our OWN player so controls feel instant
      gInputAcc+=dt; if(gInputAcc>=0.018){ gInputAcc=0; sendGuestInput(); }   // ~55Hz input (snappier control)
      applyNetState();                    // also reads the host's slow-mo flag -> netSlowmo
      motionScale += ((netSlowmo?GOAL_SLOWMO_SCALE:1) - motionScale)*0.2;   // SMOOTH slow-mo: ease the per-frame motion scale (no frame-skip)
      if(!halftime) predictGuestSelf();   // freeze our own player during the half-time break
      updateHUD();
    } else {
      if(goalLock>0)goalLock--;
      else if(!golden && !halftime){
        timeLeft-=dt;                      // match clock stays REAL-TIME — slow-mo never touches it
        if(timeLeft<=0){ timeLeft=0; onTimeUp(); }
      }
      maybeArmSlowmo();                    // arm slow-mo as a gated, goal-bound shot enters the zone
      motionScale += ((isSlowmo()?GOAL_SLOWMO_SCALE:1) - motionScale)*0.2;   // SMOOTH slow-mo: ease per-frame motion (no frame-skip -> no buffering)
      if(slowmoT>0) slowmoT-=dt;           // count the slow-mo window down in real time
      if(!halftime){                       // freeze the whole pitch during the half-time break
        controlPlayer(players.p);
        if(netRole==='host') controlNet(players.t);
        else if(oppActive){ if(mode==='2p')controlPlayer(players.t); else aiControl(players.t); }
        footsteps(players.p); if(oppActive) footsteps(players.t);
        processLunges();          // b85: detect lunge contact -> clean ball-win or foul/card/reset (authoritative; guest mirrors)
        separatePlayers();
        updatePossession();
        if(goalLock<=0 && !golden){ if(ball.owner==='p') possP+=dt; else if(ball.owner==='t') possT+=dt; }
        if(ball.owner) glueBall();
        else { if(ball.kickLock<=0 || ball.kicker!=='p') ballPlayer(players.p);
               if(oppActive && (ball.kickLock<=0 || ball.kicker!=='t')) ballPlayer(players.t);
               stepBall(); }
      }
      updateHUD();
      // keep streaming even while frozen so the guest sees ht=1 (freeze) then ht=0 (resume)
      if(netRole==='host'){ stateSendAcc+=dt; if(stateSendAcc>=SNAP_INTERVAL_S){ stateSendAcc-=SNAP_INTERVAL_S; if(stateSendAcc>SNAP_INTERVAL_S) stateSendAcc=0; sendState(); } }   // steady 60Hz (keep the remainder, don't reset -> less send-cadence jitter)
    }
    // round-trip ping for the on-screen latency readout (both roles)
    if(netRole){ pingAcc+=dt; if(pingAcc>=0.34){ pingAcc=0; NET.relay({ping:performance.now()}); }   // ~3Hz so the adaptive buffer reacts fast
      pingDispAcc+=dt; if(pingDispAcc>=1.0){ pingDispAcc=0; NET.rttShown=(NET.rttDisp!=null?NET.rttDisp:NET.rtt); } }   // show the HONEST RTT (b80), 1Hz
  }
  // advance the goal juice (visual only, both roles). The slow-mo scales the FX clock too; the match clock stays real-time.
  let fxDt = isSlowmo() ? dt*GOAL_SLOWMO_SCALE : dt;
  updateGoalFx(fxDt);
  draw();
}

// ---- Accounts (saved locally in this browser) ----
const MEM={}, $=id=>document.getElementById(id);
const DB={
  get(k){ try{const v=localStorage.getItem(k); return v?JSON.parse(v):null;}catch(e){ return (k in MEM)?MEM[k]:null; } },
  set(k,v){ try{localStorage.setItem(k,JSON.stringify(v));}catch(e){ MEM[k]=v; } }
};
let account=null, ranked=false, matchTimer=null, quickTimer=null, quickMode=false, quickStruggle=false;
const accounts=()=>DB.get('sh_accts')||{};
const saveAccts=a=>DB.set('sh_accts',a);
const shortAddr=a=>a?(a.slice(0,4)+'…'+a.slice(-4)):'';
const validSol=a=>/^[1-9A-HJ-NP-Za-km-z]{32,44}$/.test(a);

function showAuth(){
  $('authScreen').classList.remove('hide'); $('startScreen').classList.add('hide'); $('splashScreen').classList.add('hide');
  $('acctBtn').classList.add('hide'); $('bellBtn').classList.add('hide'); setMenuDocks(false);
  const last=DB.get('sh_last');
  if(last && accounts()[last.toLowerCase()]) showLogin(last); else showReg();
}
function showReg(){ $('regView').style.display=''; $('loginView').style.display='none'; $('signinView').style.display='none';
  $('toLoginLink').style.display = DB.get('sh_last')?'block':'none'; $('regErr').textContent=''; showGuestCount(); }
function showLogin(u){ const a=accounts()[(u||'').toLowerCase()]; if(!a){showReg();return;}
  $('regView').style.display='none'; $('signinView').style.display='none'; $('loginView').style.display='';
  $('loginName').textContent=a.username; $('loginAddr').textContent=shortAddr(a.addr);
  $('loginPin').value=''; $('loginErr').textContent=''; setTimeout(()=>$('loginPin').focus(),60); }

// fully detach the previous online identity so a new/other account signs in cleanly
async function resetOnlineSession(){
  try{ if(sb) await sb.auth.signOut(); }catch(e){}
  [presence,inboxChan,notifyChan,chatChan,freqChan,chatPairChan].forEach(c=>{ if(c&&sb){ try{sb.removeChannel(c);}catch(e){} } });
  presence=null; inboxChan=null; notifyChan=null; chatChan=null; freqChan=null; chatPairChan=null;
  sbUser=null; onlineSet=new Set(); friendSet=new Set(); unread={}; cnotes=[]; freqs=[];
}
function doRegister(){
  const addr=$('regAddr').value.trim(), user=$('regUser').value.trim(),
        pin=$('regPin').value, pin2=$('regPin2').value, e=$('regErr');
  if(!validSol(addr)){ e.textContent='Enter a valid Solana receive address.'; return; }
  if(user.length<3){ e.textContent='Username needs at least 3 characters.'; return; }
  if(accounts()[user.toLowerCase()]){ e.textContent='That username already exists on this device.'; return; }
  if(!/^\d{4}$/.test(pin)){ e.textContent='PIN must be exactly 4 digits.'; return; }
  if(pin!==pin2){ e.textContent='PINs do not match.'; return; }
  const a=accounts(); a[user.toLowerCase()]={username:user, addr, pin, wins:0, losses:0, xp:0, coins:1000, created:Date.now()};
  saveAccts(a); DB.set('sh_last',user); account=a[user.toLowerCase()];
  resetOnlineSession().then(enterLobby);     // sign the new account into the online layer cleanly
}
// auto-fill the Solana receive address straight from the Phantom wallet
async function connectPhantom(){
  const e=$('regErr');
  const prov=(window.phantom&&window.phantom.solana)||(window.solana&&window.solana.isPhantom?window.solana:null);
  if(!prov){ e.textContent='Phantom not found — open this page in the Phantom app browser, or install the Phantom extension.';
    try{ window.open('https://phantom.app/','_blank'); }catch(_){} return; }
  try{ const res=await prov.connect(); $('regAddr').value=res.publicKey.toString(); e.textContent=''; }
  catch(err){ e.textContent='Phantom connection was cancelled.'; }
}
// jump straight in — no wallet, no username; you become goy<global guest number>
async function playAsGuest(){
  let n=null;
  if(sb){ try{ const r=await sb.rpc('bump_counter',{p_name:'guests'}); if(r && r.data!=null) n=r.data; }catch(_){} }
  if(n==null) n=Math.floor(Date.now()/1000)%100000;     // offline fallback
  const uname='goy'+n, pin=''+Math.floor(1000+Math.random()*9000);
  const a=accounts(); a[uname.toLowerCase()]={username:uname, addr:'', pin, wins:0, losses:0, xp:0, guest:true, created:Date.now()};
  saveAccts(a); DB.set('sh_last',uname); account=a[uname.toLowerCase()];
  resetOnlineSession().then(enterLobby);
}
// show how many people have played as guests, on the login screen
async function showGuestCount(){
  const el=$('guestCount'); if(!el) return;
  if(!sb){ el.textContent=''; return; }
  try{ const r=await sb.rpc('get_counter',{p_name:'guests'}); const c=(r && r.data!=null)?Number(r.data):0;
    el.textContent = c>0 ? (c.toLocaleString()+' players have jumped in as guests') : 'Be the first to jump in as a guest';
  }catch(_){ el.textContent=''; }
}
// guest upgrades to a real wallet to enter the hourly 0.1 SOL leaderboard giveaway
async function guestAddWallet(){
  let addr='';
  const prov=(window.phantom&&window.phantom.solana)||(window.solana&&window.solana.isPhantom?window.solana:null);
  if(prov){ try{ const r=await prov.connect(); addr=r.publicKey.toString(); }catch(_){ } }
  if(!addr){ addr=(window.prompt('Paste your Solana receive address to enter the hourly 0.1 SOL giveaway:')||'').trim(); }
  if(!addr) return;
  if(!validSol(addr)){ showToast('That is not a valid Solana address.','#ff8787'); return; }
  account.addr=addr; account.guest=false;
  const a=accounts(); a[account.username.toLowerCase()]=account; saveAccts(a);
  // push the wallet to Supabase now if we're online; otherwise ensureOnline() upserts it next time.
  if(sb && sbUser){ try{ await sb.from('profiles').update({wallet:addr}).eq('id',sbUser.id); }catch(_){} }
  else if(sb){ try{ await ensureOnline(); }catch(_){} }
  showToast("Wallet added — you're in the hourly 0.1 SOL giveaway! 🎉",'#69db7c');
  refreshGuestBanner(); refreshAcctBtn();
}
function refreshGuestBanner(){
  const b=$('guestBanner'); if(!b) return;
  b.classList.toggle('hide', !(account && account.guest && !account.addr));
}
function doLogin(){
  const last=DB.get('sh_last'), a=accounts()[(last||'').toLowerCase()], pin=$('loginPin').value;
  if(a && a.pin===pin){ account=a; resetOnlineSession().then(enterLobby); }
  else { $('loginErr').textContent='Wrong PIN.'; $('loginPin').value=''; }
}
function logout(){ account=null; resetOnlineSession();
  $('acctBtn').classList.add('hide'); $('bellBtn').classList.add('hide');
  $('startScreen').classList.add('hide'); $('profileScreen').classList.add('hide'); showReg();
  $('authScreen').classList.remove('hide'); }
function avatarOf(username){ return DB.get('sh_pic_'+(username||'').toLowerCase())||''; }

// ---- XP & levels ----
function levelFromXp(xp){ let L=1, into=xp||0, need=100;
  while(into>=need){ into-=need; L++; need=100*L; } return {level:L, into, need}; }
function refreshAcctBtn(){
  if(!account){ $('acctBtn').classList.add('hide'); $('bellBtn').classList.add('hide'); return; }
  $('acctName').textContent=account.username;
  $('acctPic').src=avatarOf(account.username);
  $('acctLvl').textContent='Lv'+levelFromXp(account.xp||0).level;
  const cc=$('acctCoins');
  if(cc){ if(account.guest){ cc.classList.add('hide'); } else { cc.innerHTML=coinIcon()+myCoins(); cc.classList.remove('hide'); } }
  $('acctBtn').classList.remove('hide'); $('bellBtn').classList.remove('hide');
  refreshGuestBanner();
  loadEquipped();                                            // per-account equipped character (local)
  if(sbUser && !_equipSynced){ _equipSynced=true; syncEquippedFromCloud(); syncCharStatsFromCloud(); }   // one-shot cross-device pull (equipped + per-char record)
}

// ---- $BASED coins (in-game currency; mirrored to Supabase profiles) ----
function coinIcon(){ return '<span class="bcoin"></span>'; }   // soccer-ball-with-$ logo
function myCoins(){ return (account&&account.coins)||0; }
function setLocalCoins(n){
  if(!account||n==null) return;
  account.coins=n;
  const a=accounts(), me=a[account.username.toLowerCase()]; if(me){ me.coins=n; saveAccts(a); }
  const cc=$('acctCoins'); if(cc && !account.guest){ cc.innerHTML=coinIcon()+n; cc.classList.remove('hide'); }
  const pc=$('profCoinsTop'); if(pc) pc.innerHTML=coinIcon()+' '+n;
}
async function syncCoins(){
  if(!sb||!sbUser) return;
  try{ const {data}=await sb.from('profiles').select('coins').eq('id',sbUser.id).single();
       if(data&&data.coins!=null) setLocalCoins(data.coins); }catch(e){}
}
// b86: MONOTONIC profile sync. The `merge_profile` RPC raises xp/wins/losses via GREATEST(), so a
// stale/empty local context can NEVER lower real cloud progress — this is the fix for the "level
// resets to 1" bug (level is derived from xp; a destructive 0-write wiped it). Awaited internally
// with one retry, replacing the old fire-and-forget `.update()`s that let cloud xp lag. Coins are
// intentionally NOT synced here — they move only through the settle_match RPC (sacred law). Safe
// no-op until the merge_profile RPC is created in Supabase, and never destructive in the meantime.
async function pushProfile(){
  if(!sb || !sbUser || !account) return false;
  const args={ p_xp:account.xp||0, p_wins:account.wins||0, p_losses:account.losses||0,
    p_wallet:account.addr||'', p_avatar:avatarOf(account.username)||'' };
  for(let i=0;i<2;i++){
    try{ const { error }=await sb.rpc('merge_profile', args); if(!error) return true; }catch(e){}
  }
  return false;
}
function onlineWagerEnabled(){ return !!(account && !account.guest && sb); }

// ---- per-player stats for achievements (local) ----
function statsKey(){ return 'sh_stats_'+(account?account.username.toLowerCase():'guest'); }
function getStats(){ return DB.get(statsKey())||{games:0,goals:0,wins:0,msgs:0,comments:0,friends:0,pic:0,unlocked:[]}; }
function saveStats(s){ DB.set(statsKey(), s); }
