// ---- cross-device sign in (username + PIN against the online account) ----
function showSignin(){ $('regView').style.display='none'; $('loginView').style.display='none';
  $('signinView').style.display=''; $('siErr').textContent=''; }
$('toSignin').onclick=showSignin;
