// ---- viewing ANOTHER player's profile (avatar, record, comments) ----
let pubTarget=null, pubBackFn=null;
async function loadComments(profileId, el){
  el.innerHTML='<div class="empty">Loading…</div>';
  if(!sb){ el.innerHTML='<div class="empty">—</div>'; return; }
  const { data } = await sb.rpc('comments_for',{p_profile:profileId, p_limit:50});
  if(!data || !data.length){ el.innerHTML='<div class="empty">No comments yet.</div>'; return; }
  el.innerHTML='';
  data.forEach(c=>{ const d=document.createElement('div'); d.className='cmt';
    d.innerHTML='<div class="ca" data-prof="'+c.author_name+'"></div><div class="cb"></div>';
    d.querySelector('.ca').textContent=c.author_name; d.querySelector('.cb').textContent=c.body;
    el.appendChild(d); });
  el.querySelectorAll('[data-prof]').forEach(b=> b.onclick=()=> openPubProfile(b.getAttribute('data-prof')) );
}
async function openPubProfile(username, back){
  if(!username) return;
  if(account && username.toLowerCase()===account.username.toLowerCase()){ openProfile(); return; }
  pubBackFn = back || (()=>{ $('startScreen').classList.remove('hide'); refreshAcctBtn(); });
  hideAllOverlays(); $('pubProfileScreen').classList.remove('hide');
  $('pubName').textContent=username; $('pubPic').src=''; $('pubRec').textContent='…';
  $('pubAddBtn').style.display='none'; $('pubAddBtn').textContent='➕ ADD FRIEND'; $('pubAddBtn').classList.remove('disabled');
  $('pubComments').innerHTML='<div class="empty">Loading…</div>';
  if(!sb){ $('pubRec').textContent='offline'; return; }
  if(!sbUser) await ensureOnline();
  const { data } = await sb.rpc('public_profile',{p_username:username});
  if(!data || !data.length){ $('pubRec').textContent='no online profile'; $('pubComments').innerHTML='<div class="empty">This player has no online profile yet.</div>'; return; }
  const p=data[0]; pubTarget={id:p.id, username:p.username};
  const plv=levelFromXp(p.xp||0).level;
  $('pubName').innerHTML=p.username+' <span class="lvlchip">Lv'+plv+'</span>';
  $('pubPic').src=p.avatar||'';
  $('pubRec').textContent=(p.wins||0)+'W · '+(p.losses||0)+'L';
  $('pubAddBtn').style.display = friendSet.has(p.username.toLowerCase()) ? 'none' : 'block';
  loadComments(p.id, $('pubComments'));
}
async function postPubComment(){
  const t=$('pubCommentInput').value.trim(); if(!t || !pubTarget) return;
  if(!sbUser){ if(!await ensureOnline()) return; }
  $('pubCommentInput').value='';
  await sb.from('comments').insert({profile_id:pubTarget.id, author_id:sbUser.id, author_name:sbUser.username, body:t});
  notifyUser(pubTarget.id, 'comment', {fromName:sbUser.username});   // ping the profile owner
  bumpStat('comments');
  loadComments(pubTarget.id, $('pubComments'));
}
$('pubBackBtn').onclick=()=>{ $('pubProfileScreen').classList.add('hide'); if(pubBackFn) pubBackFn(); };
$('pubAddBtn').onclick=()=>{ if(pubTarget){ addFriend(pubTarget.username); $('pubAddBtn').textContent='REQUEST SENT'; $('pubAddBtn').classList.add('disabled'); } };
