// AUTO-LOADED at match time from /api/turn (Cloudflare TURN, short-lived creds minted server-side; the key secret never
// ships to the browser). EMPTY = STUN-only fallback (e.g. /api/turn not configured yet) — never breaks. To turn it ON, set
// TURN_KEY_ID + TURN_KEY_API_TOKEN in the Vercel project env vars (see api/turn.js), then redeploy.
let TURN_SERVERS=[];
async function loadTurn(){
  if(typeof fetch!=='function' || !(location.protocol==='http:'||location.protocol==='https:')) return;   // hosted only
  if(TURN_SERVERS.length && (Date.now()-(loadTurn._at||0) < 3600000)) return;   // cache ~1h (creds are short-lived; refetch hourly)
  try{ const r=await fetch(location.origin+'/api/turn',{cache:'no-store'}); if(!r.ok) return;
    const d=await r.json();
    if(d && d.iceServers){
      const arr = Array.isArray(d.iceServers)?d.iceServers:[d.iceServers];
      // UDP-ONLY (b80): keep stun + turn-over-udp, drop turn-tcp / turns-tls. Fewer relay candidates means a
      // DIRECT (srflx) pair isn't drowned out in nomination, and any relay we DO use is low-latency UDP (the
      // TCP/TLS relay paths were what made the fallback 500ms+). prefer-direct (b79) still declines relay anyway.
      TURN_SERVERS = arr.map(s=>{ if(!s.urls) return s;
          const u=(Array.isArray(s.urls)?s.urls:[s.urls]).filter(x=> x.indexOf('stun:')===0 || (x.indexOf('turn:')===0 && /transport=udp/.test(x)));
          return Object.assign({}, s, {urls:u}); }).filter(s=> s.urls && s.urls.length);
      loadTurn._at=Date.now();
      if(P2P_DEBUG) console.log('[p2p] TURN loaded from /api/turn — UDP-only ('+TURN_SERVERS.length+' server(s))'); }
    else if(P2P_DEBUG) console.log('[p2p] /api/turn returned no creds — STUN-only (set TURN_KEY_ID + TURN_KEY_API_TOKEN in Vercel)');
  }catch(e){}
}
