// ---- wager handshake (rides the existing relay; no lobby-server changes needed) ----
// HOST announces the match (+ its stake, id, and a shared matchId). The amount is
// finalised when the guest acks (we learn the guest's id + agreed stake then).
function sendHostStart(){
  const stk = onlineWagerEnabled() ? stakeSel : 0;
  const mid = (NET.code||'m')+'-'+Date.now().toString(36)+Math.floor(Math.random()*1e6).toString(36);
  wager = { amount:0, oppId:null, matchId:mid, settled:false };
  // a guest never advertises a settlement id -> no wager AND no faucet for either side (casual)
  const myId = (sbUser && account && !account.guest) ? sbUser.id : null;
  NET.relay({ start:{ hostChar:humanChar, hostName:(account?account.username:''), mode:gameMode,
                      stake:stk, hostId:myId, matchId:mid } });
  updatePotTag();
}
// GUEST receives the host's start: agree on min(both stakes), then ack with our id.
function setupGuestWager(start){
  const hostStake=start.stake||0, hostId=start.hostId||null;
  const myStake = (onlineKind==='quick') ? stakeSel : hostStake;   // friend guest accepts host's stake
  let amount = Math.max(0, Math.min(hostStake, myStake));
  if(!onlineWagerEnabled() || !sbUser || !hostId || amount>myCoins()) amount=0;
  const myId = (sbUser && account && !account.guest) ? sbUser.id : null;  // guests stay casual
  // BUILD 1: the guest always plays its own LOCKER-equipped character (quick, wager AND friend).
  const guestChar = (STATS[equippedChar] ? equippedChar : 'pepe');
  oppChar = guestChar;   // we (guest) control players.t = guestChar; players.p = host's char
  wager = { amount, oppId:hostId, matchId:start.matchId||null, settled:false };
  NET.relay({ wagerAck:{ amount, stake:myStake, guestId:myId, char:guestChar } });   // tell host our character
  updatePotTag();   // wager is shown in the framed match banner, not a floating toast
}
// settle at match end: both peers report their perceived winner; coins (faucet + any
// wager) move only when BOTH confirm the same match — see sql/social-schema-add5.sql.
async function settleWager(win){
  if(!netRole || !sb || !sbUser || !account || account.guest) return;  // guests are casual-only: no coins ever
  if(!wager.oppId || !wager.matchId || wager.settled) return;
  wager.settled=true;
  const amt=wager.amount||0;
  const args={ p_match:wager.matchId, p_opponent:wager.oppId, p_amount:amt, p_winner:(win?sbUser.id:wager.oppId) };
  const append=html=>{ const el=$('xpSummary'); if(el){ el.classList.remove('hide'); el.insertAdjacentHTML('beforeend', html); } };
  try{
    let { data } = await sb.rpc('settle_match', args);
    if(data && data.status==='pending'){                 // opponent's report not in yet — retry once
      await new Promise(r=>setTimeout(r,1600));
      ({ data } = await sb.rpc('settle_match', args));
    }
    data=data||{};
    if(data.coins!=null) setLocalCoins(data.coins); else await syncCoins();
    if(data.wager==='won') bumpStat('wagersWon');
    let line;
    if(amt>0 && data.wager==='won')  line='<div class="xline"><span>'+coinIcon()+' Wager won</span><b style="color:#69db7c">+'+amt+' $BASED</b></div>';
    else if(amt>0 && data.wager==='lost') line='<div class="xline"><span>'+coinIcon()+' Wager lost</span><b style="color:#ff8787">−'+amt+' $BASED</b></div>';
    else if(amt>0 && data.status==='pending') line='<div class="xline"><span>'+coinIcon()+' Wager</span><b>opponent didn’t confirm — voided</b></div>';
    else if(amt>0) line='<div class="xline"><span>'+coinIcon()+' Wager void</span><b>no coins moved</b></div>';
    else line='<div class="xline"><span>'+coinIcon()+' $BASED</span><b>balance '+myCoins()+'</b></div>';
    append(line);
  }catch(e){ try{ await syncCoins(); }catch(_){ } }
}

function beginGameOnline(role){ showLoadingThen(()=>_beginGameOnline(role)); }   // 5s loading, then start
function _beginGameOnline(role){
  netRole=role; oppActive=true; ranked=true; mode='online';
  NET.reconnTries=0; NET.intentionalClose=false;   // fresh match — reset reconnect state
  netKickPrev=false; NET.state=null; NET.buf=[]; stateSendAcc=0; gInputAcc=0;
  NET.guestInput={ax:0,ay:0,aim:Math.PI,sprint:false,kick:false};
  recordOpponent(NET.peerName);
  hideAllOverlays();   // BUGFIX (b73): hide EVERY menu overlay — the old explicit list missed the PLAY hub (modeSelectScreen) + wager screen, leaving them painted over the live match
  $('acctBtn').classList.add('hide'); $('bellBtn').classList.add('hide');
  $('hud').classList.remove('hide'); $('liveCountHud').classList.remove('hide'); setMenuDocks(false); $('pCard').classList.remove('hide'); $('tCard').classList.remove('hide');
  $('pauseBtn').textContent='❚❚'; enterMatchChrome();
  const oc = oppChar || (humanChar==='pepe'?'trumpe':'pepe');
  $('pCard').querySelector('.pc-name').textContent = role==='host' ? (account?account.username:STATS[humanChar].name) : (NET.peerName||STATS[humanChar].name);
  $('tCard').querySelector('.pc-name').textContent = role==='guest' ? (account?account.username:STATS[oc].name) : (NET.peerName||STATS[oc].name);
  $('pTeam').textContent=STATS[humanChar].abbr; $('tTeam').textContent=STATS[oc].abbr;
  newGame(); gpInit(); lastTs=performance.now(); state='play'; audioInit(); stopMusic();
  showMatchBanner();
}
// host applies the guest's streamed input to the right-side player
let netLungePrev=false;
function controlNet(pl){
  const gi=NET.guestInput;
  pl.aim = gi.aim;
  if(gi.lunge && !netLungePrev){ tryLunge(pl); }   // b85: edge-trigger the guest's lunge on the host (authoritative; foul check follows)
  netLungePrev = !!gi.lunge;
  applyMove(pl, gi.ax, gi.ay, gi.sprint);
  chargeKick(pl, !!gi.kick);     // host charges/fires from the guest's held button
  netKickPrev = gi.kick;
}
// guest reads local input and streams it to the host
let guestAim=Math.PI;
function sendGuestInput(){
  let ax=0,ay=0;
  if(keys['w'])ay-=1; if(keys['s'])ay+=1; if(keys['a'])ax-=1; if(keys['d'])ax+=1;
  if(joyActive){ax+=joyVec.x;ay+=joyVec.y;}
  const m=Math.hypot(ax,ay); if(m>1){ax/=m;ay/=m;}
  const t=players.t;
  // aim: on a phone there is no mouse — point where the joystick points (and HOLD that heading
  // when the stick is released) instead of leaving the arrow frozen at the stale mouse position.
  if(IS_TOUCH){ if(joyActive && (joyVec.x||joyVec.y)) guestAim=Math.atan2(joyVec.y,joyVec.x); }
  else guestAim=Math.atan2(mouse.y-t.y, mouse.x-t.x);
  const lunge=lungeReq; if(lunge){ lungeReq=false; guestPredictLunge(); }   // b85: send the lunge edge to the host + predict it locally so it feels instant
  NET.relay({ input:{ ax, ay, aim:guestAim,
    sprint:!!(keys['shiftleft']||keys['shift']||touchSprint),
    kick:!!(keys['kick']||touchKick), lunge:lunge } });
}
// host streams the authoritative snapshot to the guest
function sendState(extra){
  const p=players.p,t=players.t;
  // round before serialising: positions to whole pixels, angles/stamina to 2dp, clock/possession
  // to 1dp. Interpolation hides the rounding, and ~35% smaller frames arrive faster on weak links.
  const R=Math.round, R2=v=>R(v*100)/100, R1=v=>R(v*10)/10;
  NET.relay({ state:{
    p:{x:R(p.x),y:R(p.y),aim:R2(p.aim),face:p.face,char:p.char,stam:R2(p.stamina),ch:R2(p.charge),cg:p.charging?1:0},
    t:{x:R(t.x),y:R(t.y),aim:R2(t.aim),face:t.face,char:t.char,stam:R2(t.stamina),ch:R2(t.charge),cg:t.charging?1:0},
    b:{x:R(ball.x),y:R(ball.y),roll:R2(ball.roll||0),dir:R2(ball.dir||0),net:ball.netSide||0,own:ball.owner||0},
    s:[score.p,score.t], tl:R1(timeLeft), gl:golden, pp:R1(possP), tp:R1(possT), gm:gameMode, hf:half, ht:halftime?1:0, st:(extra&&extra.st)||'play', win:(extra&&extra.win)||0, rq:rebSeq, rs:rebLastSide, gq:goalSeq, gsd:goalFxSide, sm:slowmoT>0?1:0, cm:slowmoCamMode==='goal'?1:0, cs:slowmoCamSide,
    fq:foulSeq, fcd:foulCardType, fws:foulCardSide, pca:players.p.cards||0, tca:players.t.cards||0, po:players.p.out?1:0, to:players.t.out?1:0   // b85: foul/card event + per-player card counts + removed flags
  }});
}
// guest buffers snapshots and renders in the past, gliding between them.
// the buffer adapts to measured ping (tight on Sydney, larger on Singapore) so motion
// stays smooth without stutter when packets arrive unevenly — see the pong handler.
// ---- Guest interpolation tunables (b84). ROOT CAUSE of the guest choppiness: the old floors
// (INTERP 44ms / BALL 20ms) were BELOW ~2 snapshots of buffer (host sends 60Hz = 16.6ms/snap), so
// normal receive jitter constantly underran the buffer -> the guest EXTRAPOLATED ("guessed") then
// SNAPPED back, choppy even on a good link. Floors raised to hold a real cushion; a little extra
// latency bought for a lot more smoothness. Still adaptive — grow under measured jitter (rtt). ----
const INTERP_FLOOR=80, INTERP_CEIL=170;   // opponent/own buffer (ms): floor ≈ 4-5 snapshots of cushion @60Hz
const BALL_FLOOR=48,  BALL_CEIL=85;       // ball buffer (ms): still responsive, but ≥2-3 snapshots of cushion
const RENDER_SNAP_PX=34;   // a per-frame render JUMP bigger than this = a discontinuity (underrun/reset) -> EASE it; smaller = track exactly (no added lag)
const RENDER_EASE=0.35;    // how fast an eased (snapped) render position closes to the true interp target, per frame
const SNAP_INTERVAL_S=1/60;// host snapshot cadence (steady the send loop instead of resetting the accumulator)
const EXTRAP_CAP_MS=100;   // on buffer underrun, continue last-known velocity for at most this long, then hold
let INTERP_DELAY=INTERP_FLOOR, BALL_DELAY=BALL_FLOOR;   // current adaptive values (set in the pong handler)
// ease only DISCONTINUITIES (snaps); track normal motion exactly so we add no lag in the common case
function smoothRender(cur,target){ if(cur==null) return target; const d=target-cur; return Math.abs(d)>RENDER_SNAP_PX ? cur+d*RENDER_EASE : target; }
function pushNetState(s){
  NET.buf.push({t:performance.now(), s});
  if(NET.buf.length>40) NET.buf.shift();   // ~0.8s of history at 50Hz — room for the adaptive buffer
  NET.state=s;
}
function nlerp(a,b,k){ return a+(b-a)*k; }
function alerp(a,b,k){ let d=b-a; while(d>Math.PI)d-=2*Math.PI; while(d<-Math.PI)d+=2*Math.PI; return a+d*k; }
// pick the two snapshots around (now - delay) and the blend factor; extrapolate briefly if a packet is late
function sampleAt(delay){
  const buf=NET.buf, rt=performance.now()-delay;
  for(let i=0;i<buf.length-1;i++){ if(buf[i].t<=rt && buf[i+1].t>=rt) return {s:buf[i].s, sb:buf[i+1].s, k:(rt-buf[i].t)/((buf[i+1].t-buf[i].t)||1)}; }
  if(buf.length>=2){ const a=buf[buf.length-2], b=buf[buf.length-1];
    const span=(b.t-a.t)||1; let ahead=rt-b.t; if(ahead<0)ahead=0; if(ahead>EXTRAP_CAP_MS)ahead=EXTRAP_CAP_MS;   // continue last velocity briefly on underrun
    let f=ahead/span; if(f>1)f=1; return {s:a.s, sb:b.s, k:1+f}; }
  const latest=buf[buf.length-1].s; return {s:latest, sb:latest, k:0};
}
function applyNetState(){
  const buf=NET.buf; if(buf.length<2) return;   // need 2 snapshots to interpolate — don't paint a lone stale frame
  const latest=buf[buf.length-1].s;
  // discrete fields come from the newest snapshot (no lag on score/clock/result)
  score.p=latest.s[0]; score.t=latest.s[1]; timeLeft=latest.tl; golden=latest.gl;
  if(latest.gm) gameMode=latest.gm; if(latest.pp!=null) possP=latest.pp; if(latest.tp!=null) possT=latest.tp;
  if(latest.rq!=null && latest.rq>rebSeen){ rebSeen=latest.rq; showToast('🎯 REBOUND +3s!', latest.rs==='p'?'#69db7c':'#ff8787'); }
  if(latest.gq!=null && latest.gq>goalSeen){ goalSeen=latest.gq; triggerGoalFx(latest.gsd||'L'); }   // detonate the goal explosion in sync with the host
  // b85: mirror the host's authoritative card counts / removed flags, and flash the card when a new foul lands
  if(latest.pca!=null) players.p.cards=latest.pca; if(latest.tca!=null) players.t.cards=latest.tca;
  players.p.out=!!latest.po; players.t.out=!!latest.to;
  if(latest.fq!=null && latest.fq>foulSeen){ foulSeen=latest.fq;
    const side=latest.fws||'p', nm=(players[side]&&STATS[players[side].char])?STATS[players[side].char].name:'';
    showCard(latest.fcd===2?'red':'yellow', nm); }
  netSlowmo = !!latest.sm;                          // follow the host's slow-mo window (drives our prediction + FX pulldown)
  if(latest.cm!=null) netCamMode = latest.cm?'goal':'ball';   // and the host's cinematic camera framing
  if(latest.cs) netCamSide = latest.cs;
  if(latest.hf){ const wasHt=halftime; half=latest.hf; halftime=!!latest.ht;
    setMeta(halftime?'HALF TIME':halfLabel());
    if(halftime && !wasHt) showHalftime();          // host hit half-time -> show our 5s screen + freeze
    else if(!halftime && wasHt) hideHalftime(); }   // host resumed -> back to play
  if(latest.st==='win' && state==='play'){ state='win'; showWinFromNet(latest.win); return; }
  // players use the normal buffer; the ball renders closer to present — EXCEPT while the opponent
  // is dribbling: then glue it to them at the SAME delay, or it floats ahead of their feet on a
  // "rubber-band leash". A free or self-dribbled ball stays near real-time so kicks feel responsive.
  const P=sampleAt(INTERP_DELAY);
  const oppHasBall = latest.b && latest.b.own==='p';
  const Bl=sampleAt(oppHasBall ? INTERP_DELAY : BALL_DELAY);
  const ap=players.p, at=players.t;
  ap.x=smoothRender(ap.x, nlerp(P.s.p.x,P.sb.p.x,P.k)); ap.y=smoothRender(ap.y, nlerp(P.s.p.y,P.sb.p.y,P.k)); ap.aim=alerp(P.s.p.aim,P.sb.p.aim,P.k);
  ap.face=P.sb.p.face; ap.char=P.sb.p.char; ap.stamina=P.sb.p.stam; ap.charge=P.sb.p.ch||0; ap.charging=!!P.sb.p.cg;
  at.x=nlerp(P.s.t.x,P.sb.t.x,P.k); at.y=nlerp(P.s.t.y,P.sb.t.y,P.k); at.aim=alerp(P.s.t.aim,P.sb.t.aim,P.k);
  at.face=P.sb.t.face; at.char=P.sb.t.char; at.stamina=P.sb.t.stam; at.charge=P.sb.t.ch||0; at.charging=!!P.sb.t.cg;
  ball.x=smoothRender(ball.x, nlerp(Bl.s.b.x,Bl.sb.b.x,Bl.k)); ball.y=smoothRender(ball.y, nlerp(Bl.s.b.y,Bl.sb.b.y,Bl.k));
  ball.roll=Bl.sb.b.roll; ball.dir=Bl.sb.b.dir; ball.netSide=Bl.sb.b.net||null; ball.owner=Bl.sb.b.own||null;
}
function showWinFromNet(who){
  // guest is the right-side player (players.t)
  if(ranked && account) recordResult(who==='t');
  $('winScreen').classList.remove('hide');
  const n=$('winName'); n.textContent= who==='p'?STATS[players.p.char].name:STATS[players.t.char].name;
  n.style.color= who==='p'?'#69db7c':'#ff8787';
  $('winMsg').textContent=(who==='t'?'You win! ':'You lost. ')+(account?account.wins+'W · '+account.losses+'L':'');
  setupEndScreen();
  awardEndOfMatch(who==='t');
}

// ---- Friends (local to this device) ----
// ============ SOCIAL: server friends + live chat (Supabase) ============
let sbUser=null, presence=null, onlineSet=new Set(), chatChan=null, chatPeer=null;

// sign into Supabase using the player's existing username+PIN (lazily)
async function ensureOnline(){
  if(!sb || !account) return false;
  if(sbUser) return true;
  const email=account.username.toLowerCase()+'@trenchmon.app';
  const password='pin_'+account.pin;
  let r=await sb.auth.signInWithPassword({email,password});
  if(r.error){
    const s=await sb.auth.signUp({email,password});
    if(s.error){ $('socialNote').textContent='That username is already taken online — pick another in your profile.'; return false; }
    r=s;
  }
  const uid=r.data && r.data.user && r.data.user.id;
  if(!uid){ if($('socialNote')) $('socialNote').textContent='Could not sign in online (check email-confirm is OFF in Supabase).'; return false; }
  // b86: ensure the row EXISTS without overwriting monotonic fields. The old upsert pushed
  // {xp:account.xp||0,...} every lobby entry, so an empty-localStorage context (new device / cleared
  // cache / different origin) clobbered real cloud progress to 0 -> level 1. Now we only upsert the
  // identity (id+username), then raise xp/wins/losses/wallet/avatar via merge_profile (GREATEST).
  await sb.from('profiles').upsert({id:uid, username:account.username});
  sbUser={id:uid, username:account.username};
  await pushProfile();  // monotonic raise — a fresh/empty context can NEVER lower cloud values
  startPresence();
  syncCoins();          // pull authoritative $BASED balance (new profiles default to 1000)
  return true;
}
// ---- live "playing now" counter: every open tab joins a shared presence channel ----
// tabChan is tab-scoped by design (random key, payload {t,region} only — never identity),
// so it deliberately survives account switches and is NOT torn down in resetOnlineSession.
let tabChan=null, liveCount=0;
function updateLiveCount(){
  const n=Math.max(1, liveCount||0);
  const m=$('liveCountMenu'); if(m) m.innerHTML='👁 <b>'+n+'</b> playing now';
  const h=$('liveCountHud');  if(h) h.textContent='👁 '+n;
}
function startTabPresence(){
  if(!sb || tabChan) return;
  try{
    const key='tab_'+Math.random().toString(36).slice(2)+Date.now().toString(36);
    tabChan=sb.channel('live_tabs', {config:{presence:{key}}});
    tabChan.on('presence',{event:'sync'},()=>{
      liveCount=Object.keys(tabChan.presenceState()).length; updateLiveCount(); });
    tabChan.subscribe(s=>{ if(s==='SUBSCRIBED') tabChan.track({t:Date.now(), region:curRegion()}); });
  }catch(e){}
  updateLiveCount();
}
function startPresence(){
  if(presence||!sbUser) return;
  presence=sb.channel('online', {config:{presence:{key:sbUser.id}}});
  presence.on('presence',{event:'sync'},()=>{
    onlineSet=new Set(Object.keys(presence.presenceState()));
    const m=DB.get('sh_lastseen')||{}, now=Date.now();   // remember when we last saw each person online
    onlineSet.forEach(id=>{ m[id]=now; }); DB.set('sh_lastseen', m);
    if(chatPeer && !$('chatScreen').classList.contains('hide')){
      $('chatStatus').textContent=chatStatusText(chatPeer.id);
      $('chatDot').className='cdot'+(onlineSet.has(chatPeer.id)?' online':''); }
    if(!$('socialScreen').classList.contains('hide')) renderFriends();
  });
  presence.subscribe(s=>{ if(s==='SUBSCRIBED') presence.track({u:sbUser.username}); });
}

async function openSocial(){
  hideAllOverlays();
  $('friendErr').textContent=''; $('friendInput').value='';
  $('socialScreen').classList.remove('hide');
  $('myHandle').textContent = account ? account.username : '—';
  renderRecentOpps();
  $('friendList').innerHTML='<div class="empty">Loading…</div>';
  if(!SOCIAL_ON()){ $('socialNote').textContent='Online social needs Supabase set up.'; renderLocalFriends(); return; }
  $('socialNote').textContent='Connecting…';
  const ok=await ensureOnline();
  if(!ok){ renderLocalFriends(); return; }
  $('socialNote').textContent='Friends sync across devices. Tap a friend to chat.';
  renderFriends();
}
let friendSet=new Set();
function renderRecentOpps(){
  const all=(DB.get('sh_recentOpps')||[]).filter(n=> !account || n.toLowerCase()!==account.username.toLowerCase());
  const box=$('recentOppBox'), list=$('recentOpps');
  if(!all.length){ box.classList.add('hide'); return; }
  box.classList.remove('hide'); list.innerHTML='';
  all.forEach(n=>{ const isF=friendSet.has(n.toLowerCase());
    const row=document.createElement('div'); row.className='frow';
    row.innerHTML='<span class="fn" data-prof="'+n+'">'+n+'</span>'
      + (isF?'<span class="fbtn pend">friend ✓</span>':'<button class="fbtn" data-add="'+n+'">ADD</button>');
    list.appendChild(row); });
  list.querySelectorAll('[data-add]').forEach(b=> b.onclick=()=> addFriend(b.getAttribute('data-add')) );
  list.querySelectorAll('[data-prof]').forEach(b=> b.onclick=()=> openPubProfile(b.getAttribute('data-prof'), openSocial) );
}
async function renderFriends(){
  if(!sbUser){ renderLocalFriends(); return; }
  const list=$('friendList');
  const { data, error } = await sb.rpc('my_friends');
  if(error){ list.innerHTML='<div class="empty">Could not load friends.</div>'; return; }
  // remember who's already a friend/pending so we don't offer to add them again
  friendSet=new Set((data||[]).map(f=>f.username.toLowerCase()));
  renderRecentOpps();
  list.innerHTML='';
  if(!data.length){ list.innerHTML='<div class="empty">No friends yet. Add someone by username above.</div>'; return; }
  data.forEach(f=>{
    const row=document.createElement('div'); row.className='frow';
    const online=onlineSet.has(f.friend_id);
    let right;
    if(f.status==='accepted') right='<button class="fbtn chal" data-chal="'+f.friend_id+'" data-cn="'+f.username+'">⚔️</button>'
      +'<button class="fbtn" data-chat="'+f.friend_id+'" data-name="'+f.username+'">CHAT</button>';
    else if(f.incoming) right='<button class="fbtn accept" data-acc="'+f.friend_id+'">ACCEPT</button>';
    else right='<span class="fbtn pend">pending</span>';
    right+='<button class="fbtn rem" data-rem="'+f.friend_id+'" data-rn="'+f.username+'" title="remove">✕</button>';
    row.innerHTML='<span class="fmeta"><span class="cdot'+(online?' online':'')+'"></span><span class="fn" data-prof="'+f.username+'">'+f.username+'</span></span>'
      +'<span class="frow-right">'+right+'</span>';
    list.appendChild(row);
  });
  list.querySelectorAll('[data-chat]').forEach(b=> b.onclick=()=>openChat(b.getAttribute('data-chat'), b.getAttribute('data-name')));
  list.querySelectorAll('[data-chal]').forEach(b=> b.onclick=()=>challengeFriend(b.getAttribute('data-chal'), b.getAttribute('data-cn')));
  list.querySelectorAll('[data-acc]').forEach(b=> b.onclick=()=>acceptFriend(b.getAttribute('data-acc')));
  list.querySelectorAll('[data-prof]').forEach(b=> b.onclick=()=> openPubProfile(b.getAttribute('data-prof'), openSocial) );
  list.querySelectorAll('[data-rem]').forEach(b=> b.onclick=()=> removeFriend(b.getAttribute('data-rem'), b.getAttribute('data-rn')) );
}
async function removeFriend(friendId, name){
  if(!sbUser) return;
  if(!confirm('Remove '+(name||'this friend')+'?')) return;
  await sb.rpc('remove_friend',{p_other:friendId});
  renderFriends();
}
async function addFriend(uname){
  const u=(uname||$('friendInput').value).trim(), e=$('friendErr');
  if(u.length<3){ e.textContent='Enter a username.'; return; }
  if(!sbUser){ if(!await ensureOnline()){ return; } }
  if(u.toLowerCase()===account.username.toLowerCase()){ e.textContent="That's you!"; return; }
  const { data, error } = await sb.rpc('find_profile',{p_username:u});
  if(error || !data || !data.length){ e.textContent='No online player with that username yet — they need to open the game (Social) online once.'; return; }
  const target=data[0].id;
  const ins=await sb.from('friendships').insert({requester:sbUser.id, addressee:target, status:'pending'});
  if(ins.error){ e.textContent='Already requested or already friends.'; }
  else { e.textContent=''; $('friendInput').value=''; bumpStat('friends'); }
  renderFriends();
}
async function acceptFriend(friendId){
  await sb.from('friendships').update({status:'accepted'}).eq('requester',friendId).eq('addressee',sbUser.id);
  refreshServerNotifs(); renderFriends();
}

// ----- chat (timestamps, typing, seen receipts, last-online) -----
let chatPairChan=null, peerTypingT=null, typingSentAt=0;
function fmtChatTime(ts){ const d=new Date(ts); let h=d.getHours(); const m=d.getMinutes();
  const ap=h>=12?'pm':'am'; h=h%12||12; return h+':'+String(m).padStart(2,'0')+ap; }
function relTime(t){ const s=Math.max(0,Math.floor((Date.now()-t)/1000));
  if(s<60)return 'just now'; if(s<3600)return Math.floor(s/60)+'m ago';
  if(s<86400)return Math.floor(s/3600)+'h ago'; return Math.floor(s/86400)+'d ago'; }
function chatStatusText(fid){
  if(onlineSet.has(fid)) return '🟢 online now';
  const t=(DB.get('sh_lastseen')||{})[fid];
  return t ? ('⚪ last seen '+relTime(t)) : '⚪ offline';
}
async function openChat(friendId, name){
  chatPeer={id:friendId, name};
  markRead(friendId);
  hideAllOverlays();
  $('chatScreen').classList.remove('hide');
  $('chatWith').textContent=name; $('chatWith').style.cursor='pointer';
  $('chatWith').onclick=()=> openPubProfile(name, ()=>openChat(friendId,name));
  $('chatInput').value='';
  $('chatDot').className='cdot'+(onlineSet.has(friendId)?' online':'');
  $('chatStatus').textContent=chatStatusText(friendId);
  $('typingName').textContent=name; $('typingInd').classList.add('hide');
  const log=$('chatLog'); log.innerHTML='<div class="empty">Loading…</div>';
  const { data } = await sb.rpc('chat_with',{p_other:friendId, p_limit:50});
  log.innerHTML='';
  (data||[]).slice().reverse().forEach(m=> addBubble(m.sender===sbUser.id, m.body, m.created_at, 'Sent'));
  log.scrollTop=log.scrollHeight;
  subscribeChat(); subscribeChatPair(friendId);
}
function addBubble(mine, text, ts, status){
  const b=document.createElement('div'); b.className='bub '+(mine?'me':'them');
  const tx=document.createElement('span'); tx.className='bub-txt'; tx.textContent=text; b.appendChild(tx);
  const meta=document.createElement('span'); meta.className='bub-meta';
  meta.innerHTML=(ts?fmtChatTime(ts):'')+(mine?' · <span class="bstat">'+(status||'Sent')+'</span>':'');
  b.appendChild(meta);
  $('chatLog').appendChild(b); $('chatLog').scrollTop=$('chatLog').scrollHeight;
  return b;
}
function markMineSeen(){ $('chatLog').querySelectorAll('.bub.me .bstat').forEach(s=>{ s.textContent='Seen ✓✓'; s.classList.add('seen'); }); }
function showPeerTyping(){ const t=$('typingInd'); if(!t)return; t.classList.remove('hide');
  $('chatLog').scrollTop=$('chatLog').scrollHeight;
  clearTimeout(peerTypingT); peerTypingT=setTimeout(()=>t.classList.add('hide'), 2500); }
function subscribeChat(){
  if(chatChan){ sb.removeChannel(chatChan); chatChan=null; }
  chatChan=sb.channel('dm:'+sbUser.id)
    .on('postgres_changes',{event:'INSERT',schema:'public',table:'messages',filter:'recipient=eq.'+sbUser.id},
      payload=>{ const m=payload.new; if(chatPeer && m.sender===chatPeer.id){
        $('typingInd').classList.add('hide');
        addBubble(false, m.body, m.created_at);
        if(chatPairChan){ try{ chatPairChan.send({type:'broadcast',event:'seen',payload:{}}); }catch(e){} }  // I saw it
      }})
    .subscribe();
}
function subscribeChatPair(otherId){
  if(chatPairChan){ try{sb.removeChannel(chatPairChan);}catch(e){} chatPairChan=null; }
  chatPairChan=sb.channel('cp:'+[sbUser.id,otherId].sort().join('_'), {config:{broadcast:{self:false}}})
    .on('broadcast',{event:'typing'}, ()=>showPeerTyping())
    .on('broadcast',{event:'seen'},  ()=>markMineSeen())
    .subscribe(s=>{ if(s==='SUBSCRIBED' && chatPairChan){ try{ chatPairChan.send({type:'broadcast',event:'seen',payload:{}}); }catch(e){} } });
}
async function sendChat(){
  const t=$('chatInput').value.trim(); if(!t||!chatPeer) return;
  $('chatInput').value='';
  addBubble(true, t, Date.now(), 'Sent');
  await sb.from('messages').insert({sender:sbUser.id, recipient:chatPeer.id, body:t});
  bumpStat('msgs');
}

// ----- local fallback (no Supabase) -----
function renderLocalFriends(){
  const a=accounts(), me=a[account.username.toLowerCase()]; account=me;
  const list=$('friendList'); list.innerHTML=''; const fr=(me&&me.friends)||[];
  if(!fr.length){ list.innerHTML='<div class="empty">No friends added yet.</div>'; return; }
  fr.forEach(u=>{ const row=document.createElement('div'); row.className='frow';
    row.innerHTML='<span class="fn">'+u+'</span>'; list.appendChild(row); });
}

